INSERT INTO public.photos VALUES (24411, 'San Juan de los Panetes aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste representando la portada de la iglesia de San Juan de los Panetes. Fuente: Lâ”œأ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65746300, -0.88131100, '0101000020E61000009E5C5320B333ECBF3FAA61BF27D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32317797271.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32317797271.webp', 'https://www.flickr.com/photos/zaragozaantigua/32317797271/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24412, 'Plaza de Huesca aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste, que muestra la torre de San Juan de los Panetes desde la plaza de Huesca, y el arco de San Juan. Fuente: Lâ”œأ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65734300, -0.88091400, '0101000020E61000005AD5928E7230ECBF94A0BFD023D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32399025396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32399025396.webp', 'https://www.flickr.com/photos/zaragozaantigua/32399025396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24661, 'Torreâ”œâ”‚n de la Zuda 1972', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. Noviembre 1972. El Torreâ”œâ”‚n de la Zuda se levantâ”œâ”‚ sobre la torre del homenaje del alcâ”œأ­zar palacio de La Sudda, La Zuda o Azuda, construido a su vez sobre uno de los torreones de la muralla romana. La Sudda fue la residencia fortificada de los gobernadores musulmanes de la taifa de Sarakusta, hasta que trasladaron su residencia oficial al palacio de la Aljaferâ”œآ،a. Tras la conquista cristina, fue residencia de los monarcas aragoneses hasta el siglo XIII, en que tambiâ”œآ®n se orientaron hacia la Aljaferâ”œآ،a. El torreâ”œâ”‚n fue reedificado en la segunda mitad del siglo XVI. La imagen actual del torreâ”œâ”‚n responde a la restauraciâ”œâ”‚n llevada a cabo por Francisco Iâ”œâ–’iguez entre 1946 y 1952, quien dio prioridad a las formas renacentistas sobre las anteriores, en coherencia con la lâ”œآ،nea historicista-regionalista de la arquitectura del Râ”œآ®gimen franquista en esos momentos. En la imagen de conjunto, el Torreâ”œâ”‚n, las murallas romanas, y el pozo que en la penâ”œâ•‘ltima intervenciâ”œâ”‚n fue llevado al Parque Grande.', 1972, 1972, 1972, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65739300, -0.88151400, '0101000020E6100000A7EA1ED95C35ECBF46CF2D7425D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14710521427.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14710521427.webp', 'https://www.flickr.com/photos/zaragozaantigua/14710521427/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24662, 'Puerta de San Ildefonso 1904', 'Colecciâ”œâ”‚n Rafael Esteban. Foto: Agustâ”œآ،n Esteban, 1904. Vista cercana de la puerta de San Ildefonso o de la Triperâ”œآ،a, tomada desde la calle de este nombre, a la orilla del Ebro. Hacia dentro, la calle Antonio Pâ”œآ®rez hacia el Mercado, con el torreâ”œâ”‚n de la Zuda arriba a la izquierda. La puerta serâ”œآ،a derribada ese mismo aâ”œâ–’o. En la puerta, un azulejo advierte que "EN ESTA CIUDAD NO SE TOLERA LA MENDICIDAD NI LA BLASFEMIA". Dicho queda.', 1904, 1904, 1904, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65779400, -0.88163500, '0101000020E61000006649809A5A36ECBFA5C0029832D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14919914990.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14919914990.webp', 'https://www.flickr.com/photos/zaragozaantigua/14919914990/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24664, 'Embarcadero del Ebro c.1925', 'Imagen de las escaleras de acceso al servicio de barca que en este tramo del râ”œآ،o permitâ”œآ،a su paso. Al fondo, San Juan de los Panetes, el torreâ”œâ”‚n de la Zuda, la calle de Antonio Pâ”œآ®rez conducente al Mercado Central, y el colegio Valentâ”œآ،n Zabala. Fuente visual: Archivo Coyne, en "El Ebro y sus riberas", Ayuntamiento de Zaragoza.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65800400, -0.88137300, '0101000020E6100000207A52263534ECBF8F519E7939D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15121638044.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15121638044.webp', 'https://www.flickr.com/photos/zaragozaantigua/15121638044/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24665, 'San Juan de los Panetes 1927', '"Rodio" (Luis Pablo Sanz Lafita) dibuja con trazos modernos y atinados una visual de San Juan de los Panetes desde la inmediata ribera del Ebro, y la acompaâ”œâ–’a de un â”œأ­rbol retorcido, una anciana crepuscular, un viejo "Ford", y un carro a la funerala. Hay nubes, sombras y claros para una composiciâ”œâ”‚n propia de un dâ”œآ،a de difuntos, tanto para los que ya lo son, como para los que lo seremos. Fuente visual: "Aragâ”œâ”‚n : revista grâ”œأ­fica de cultura aragonesa" (Aâ”œâ–’o III, Nâ”¬â•‘ 20, mayo 1927).', 1927, 1927, 1927, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65771500, -0.88075300, '0101000020E61000000D535BEA202FECBF598B4F0130D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15480634399.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15480634399.webp', 'https://www.flickr.com/photos/zaragozaantigua/15480634399/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24666, 'La Zuda 1987', 'Luis Mâ”œآ،nguez. 1987. Desde el Torreâ”œâ”‚n de la Zuda, un vistazo al Suroeste, siguiendo la Avenida de Câ”œآ®sar Augusto, por encima de los cubos ultrasemicirculares de la Murallas Romanas del s.III, la antigua plaza de Lanuza, el Mercado Central, hasta llegar a la câ”œâ•‘pula de Santiago el Mayor, al fondo. A su derecha, la iglesia de los Escolapios. Hegemonâ”œآ،a espacial del trâ”œأ­fico rodado, en movimiento, y aparcado. Solares en barbecho.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65752400, -0.88159400, '0101000020E6100000C231CB9E0436ECBFE52A16BF29D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15667970199.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15667970199.webp', 'https://www.flickr.com/photos/zaragozaantigua/15667970199/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24667, 'Plaza de Huesca 1925', 'Miguel Faci Abad. 1920-1925. "Zaragoza. Antigua plaza Huesca ante la iglesia de San Juan de los Panetes". La plaza de Huesca era una placica al lado de la plaza del Pilar, entre las calles de la Zuda (izquierda), de la Regla (donde los adoquines), de Agustinos (enfrente a â”œآ®sta), y del Fin (derecha). Esta â”œâ•‘ltima comunicaba, por medio de un antiguo trenque, con el paseo de la ribera. Al fondo, otra puerta daba entrada al recinto donde se levantaba San Juan de los Panetes. La clase social que aquâ”œآ، vivâ”œآ،a era sustancialmente diferente a la de la vecina plaza del Pilar, como reflejan los tipos y situaciones que la imagen captura, impensables apenas 100 metros hacia la derecha, en el "salâ”œâ”‚n de la ciudad". Es uno de esos dâ”œآ،as en que la sombra apetece mâ”œأ­s que la solana, y un cabrero ordeâ”œâ–’a a una chiva del rebaâ”œâ–’o, mientras unos chavales callejean a su gusto. Estos â”œأ­rboles no eran tampoco como los de la plaza del Pilar. Fuente visual: "Miguel y Gabriel Faci. Fotâ”œâ”‚grafos fundadores de la Real Sociedad Fotogrâ”œأ­fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaciâ”œâ”‚n Provincial de Zaragoza, 1999.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65722900, -0.88085200, '0101000020E6100000D8B79388F02FECBFCC7D721420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15789998832.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15789998832.webp', 'https://www.flickr.com/photos/zaragozaantigua/15789998832/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24669, 'Murallas romanas 1987', 'Luis Mâ”œآ،nguez. 1987. Desde un â”œâ”‚culo de la octogonal, barroca, inclinada y enladrillada torre de San Juan de los Panetes, una insâ”œâ”‚lita mirada sobre el entorno. Inmediato, el incontingente aparcamiento. A la izquierda, el salvado Mercado Central. Enfrente, los recios lienzos de la muralla de piedra, y el vacâ”œآ،o dejado en su pedestal por el casi semoviente Câ”œآ®sar Augusto primaportado y mussolâ”œآ،niano. Al fondo, la rotunda fachada de la original "Poblaciâ”œâ”‚n" (San Pablo), y su inmemorial acceso por la calle de Predicadores. Plagado de publicidad comercial, un enorme solar esquinado a la avenida y a la calle Ben Aire, en modo espera.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65723400, -0.88186700, '0101000020E6100000027E8D244138ECBFDEE8633E20D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15834431621.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15834431621.webp', 'https://www.flickr.com/photos/zaragozaantigua/15834431621/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24670, 'San Juan de los Panetes 1927', 'Imagen a cierta altura de la octogonal y barroca torre de San Juan de los Panetes, emergente en el entorno de callejas y recovecos que caracterizaba esta zonba, junto a la plaza de Huesca, desde la que se accedâ”œآ،a por la calle de Agustinos (izquierda), tras cruzar un pequeâ”œâ–’o arco de medio punto. Esta torre se apoyaba en construcciones que se le habâ”œآ،an ido anexando en el transcurso de los siglos. La imagen estâ”œأ­ tomada, precisamente, desde la altura de una de estas viviendas, la nâ”¬â•‘ 35 recayente al paseo del Ebro. A la derecha destaca por su altura el tejado a doble vertiente de la nave central de la iglesia, y algunos de sus contrafuertes de refuerzo. Enfrente, viviendas del nâ”¬â•‘ 11 de la calle de La Zuda y dependencias del, hasta hace poco, antiguo convento de las Adoratrices. El Torreâ”œâ”‚n de la Zuda queda un poco hacia la derecha, y, como las murallas romanas, rodeado de un compost de edificaciones. Cuando unos aâ”œâ–’os despuâ”œآ®s, se inicien obras para abrir calles y despejar la zona, la torre presentarâ”œأ­ graves problemas de estabilidad por la merma de sus tradicionales apoyos. El Ayuntamiento del momento estaba decidido a su derribo para construir un mercado en el lugar, pero mientras tanto, se proclamâ”œâ”‚ la Segunda Repâ”œâ•‘blica, y el nuevo Gobierno declarâ”œâ”‚ el templo como Monumento Nacional. Fuente visual: Instituto Amatller de Arte Hispâ”œأ­nico (Arxiu Mas). Fuente textual: Ascensiâ”œâ”‚n Hernâ”œأ­ndez Martâ”œآ،nez, "De restauraciones, demoliciones y otros debates sobre el patrimonio monumental zaragozano del siglo XX", IFC, 2008.', 1927, 1927, 1927, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15893540992.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15893540992.webp', 'https://www.flickr.com/photos/zaragozaantigua/15893540992/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24105, 'Jardâ”œآ،n de Invierno 1960', 'Imagen capturada en el "auditorium" (sic) del Jardâ”œآ،n de Invierno en el parque de Primo de Rivera durante la solemne celebraciâ”œâ”‚n del aniversario 55 de la "coronaciâ”œâ”‚n canâ”œâ”‚nica de la Virgen del Pilar" que, a iniciativa del Ayuntamiento, consistiâ”œâ”‚ en una misa con rito pontifical oficiada por el arzobispo Casimiro Morcillo. Al fondo, escenario donde se instalâ”œâ”‚ el altar con la imagen procesional en plata de la Virgen, y una gran cruz de cinco metros de altura iluminada por reflectores que presidâ”œآ،a la ceremonia. A la derecha, banderas de Acciâ”œâ”‚n Catâ”œâ”‚lica, y a la izquierda, representaciâ”œâ”‚n de seminaristas. Sobre el firme, espacio para el pâ”œâ•‘blico asistente, al frente del cual se colocaron bancos para las autoridades (entre ellas la Corporaciâ”œâ”‚n municipal encabezada por el alcalde Luis Gâ”œâ”‚mez Laguna; la Corporaciâ”œâ”‚n provincial con el presidente Antonio Zubiri Vidal; el gobernador civil y jefe provincial del "Movimiento" Josâ”œآ® Manuel Pardo de Santayana; y autoridades militares encabezadas por el capitâ”œأ­n general Manuel Baturone Colombo), ademâ”œأ­s de mil sillas de pago. Este evento comenzâ”œâ”‚ a las 20:00h. y terminâ”œâ”‚ a las 22:00h. del dâ”œآ،a 20 de mayo de ese aâ”œâ–’o.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63175500, -0.89290700, '0101000020E6100000B7D26BB3B192ECBFD00A0C59DDD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51653859433.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51653859433.webp', 'https://www.flickr.com/photos/zaragozaantigua/51653859433/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24671, 'Paseo del Ebro c.1900', 'Tener el Pilar a las espaldas, tras el Callejâ”œâ”‚n del Retiro Alto, tampoco es mala cosa a la hora de capturar instantâ”œأ­neas en Zaragoza, en este caso, desde altura, y mirando hacia el Puente del Ferrocarril (al fondo). A la derecha, Macanaz-Ranillas, con un brazal de la acequia de Juslibol desaguando al Ebro. En el despejado Paseo, una unidad de la Lâ”œآ،nea de Circunvalaciâ”œâ”‚n, a propulsiâ”œâ”‚n de sangre, dirigiâ”œآ®ndose hacia la mitad de su periplo a lo Sâ”œآ،sifo. Un jinete solitario completa el trâ”œأ­fico rodado en velocidad. A la izquierda, junto a la Puerta del Fin, un destacado concesionario de â”œآ®quidos, mulos, y carros, con alto y animado volumen comercial. Al otro lado de la calle del Fin, el entramado de calles que configura las traseras de la plaza de Huesca: Agustinos, de la Regla, de la Zuda, de las Flores... un espacio urbano complejo e irrepetible, con elementos desaparecidos, como el Colegio de los Agustinos Descalzos de San Nicolâ”œأ­s de Tolentino, la iglesia de San Antâ”œâ”‚n, el Hospital de San Juan de los Panetes... ademâ”œأ­s de todas las casas donde los prostituidores desfogâ”œأ­banse a sus anchas, a cambio de unos dineros, en otro tipo de comercio de la carne. Superviven la reorientada, modificada y barroca torre e iglesia de San Juan de los Panetes, y el torreâ”œâ”‚n de la Zuda, que sobresale tras la iglesia, por encima de vestigios de muralla romana. Fuente visual: AHPZ, Archivo Coyne, ca. 1900', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65749900, -0.87979600, '0101000020E61000000ADAE4F04927ECBF8C135FED28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16451696592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16451696592.webp', 'https://www.flickr.com/photos/zaragozaantigua/16451696592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24672, 'Plaza del Mercado 1975', 'Desde el Torreâ”œâ”‚n de la Zuda, vista de la plaza de Lanuza. Estamos en la linde entre la parroquia del Pilar, a la izquierda, y la de San Pablo, a la derecha. Al fondo, la câ”œâ•‘pula de Santiago el Mayor y siluetas de los monstruos edilicios que van surgiendo como edificios singulares y actuaciones aisladas. En primer tâ”œآ®rmino, las murallas romanas, seguidas del Mercado Central, y de la manzana entre las calles de Cerdâ”œأ­n y de las Escuelas Pâ”œآ،as.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65752400, -0.88159400, '0101000020E6100000C231CB9E0436ECBFE52A16BF29D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19025863396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19025863396.webp', 'https://www.flickr.com/photos/zaragozaantigua/19025863396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24673, 'Puerta del Fin 1922', 'Dibujo de Dâ”œآ،az Domâ”œآ،nguez del rincâ”œâ”‚n del paseo del Ebro de Zaragoza a la altura de la calle del Fin (tras la garita del fielato). Esta calle era uno de los accesos a la ciudad, cerrado con su puerta, que daba nombre a toda la explanada, utilizada como feria del ganado. El edificio donde se encuentra el negocio del veterinario Remacha habâ”œآ،a sido Colegio de los Agustinos, vulgo Agustinicos. Al fondo, la torreta de la câ”œâ•‘pula de San Juan de los Panetes. Fuente: La Cadiera 114, 1957.', 1922, 1922, 1922, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65749900, -0.87979600, '0101000020E61000000ADAE4F04927ECBF8C135FED28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20057942382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20057942382.webp', 'https://www.flickr.com/photos/zaragozaantigua/20057942382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24674, 'San Juan de los Panetes 1988', 'Foto Eduardo Zamarripa, 1988. Vista aâ”œآ®rea del torreâ”œâ”‚n de la Zuda y la iglesia de San Juan de los Panetes de Zaragoza en 1988. Fuente: Aragâ”œâ”‚n desde el aire, Ministerio de Defensa, 1988.', 1988, 1988, 1988, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20325163741.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20325163741.webp', 'https://www.flickr.com/photos/zaragozaantigua/20325163741/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24677, 'Paseo del Ebro 1926', 'Imagen del paseo del Ebro en la zona cercana a las traseras del convento de San Juan de los Panetes, entre las calles de Antonio Pâ”œآ®rez, y la del Fin, con notable proliferaciâ”œâ”‚n de caballerâ”œآ،as y carros. Despunta la linterna y el â”œأ­bside principal de la barroca iglesia de San Juan. Al fondo, el chaflâ”œأ­n del colegio Valentâ”œآ،n Zabala. Fuente visual: Miguel Marâ”œآ،n Chivite, AMZ', 1926, 1926, 1926, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65759400, -0.88028000, '0101000020E610000008556AF6402BECBFDE054A0A2CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24505950831.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24505950831.webp', 'https://www.flickr.com/photos/zaragozaantigua/24505950831/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24679, 'Cruz de los caâ”œآ،dos 1971', 'Foto: Iâ”œâ–’aki Urbez. Vista de la Cruz de los caâ”œآ،dos y el entorno de San Juan de los Panetes, desde la torre de San Francisco de Borja del Pilar. Fuente: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1971, 1971, 1971, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65726000, -0.88086300, '0101000020E6100000D234289A0730ECBF077C7E1821D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29653584062.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29653584062.webp', 'https://www.flickr.com/photos/zaragozaantigua/29653584062/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24680, 'San Juan de los Panetes c.1925', 'Imagen capturada desde la margen izquierda del râ”œآ،o Ebro, en la arboleda de Macanaz, frente a la iglesia de San Juan de los Panetes y la embocadura a la calle de Antonio Pâ”œآ®rez. A la derecha, asoma levemente el torreâ”œâ”‚n de la Zuda. Destacan las escaleras de acceso a las barcas que daban servicio de paso en este tramo del râ”œآ،o. El gran agujero abovedado en el pretil recuerda el antiguo desagâ”œâ•‌e que aquâ”œآ، vertâ”œآ،a desde la antigua plaza del Mercado. Fuente: fotografâ”œآ،a de Claudi Carbonell Flo, en www.museunacional.cat/', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65801400, -0.88160800, '0101000020E6100000008BFCFA2136ECBFB32781CD39D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30134489963.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30134489963.webp', 'https://www.flickr.com/photos/zaragozaantigua/30134489963/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24683, 'La Zuda 1882', 'Grabado con diseâ”œâ–’o de Bernardo Rico, basado en una fotografâ”œآ،a de Jean Laurent capturada en la calle de Antonio Pâ”œآ®rez, y titulado "Zaragoza.-El torreâ”œâ”‚n de la Azuda donde se firmâ”œâ”‚ la rendiciâ”œâ”‚n de la ciudad â”œأ­ Don Alfonso I â”¬آ½El Batalladorâ”¬â•— (1118)". Fuente visual: La Ilustraciâ”œâ”‚n espaâ”œâ–’ola y americana (1882)', 1882, 1882, 1882, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65756000, -0.88160100, '0101000020E610000061DEE34C1336ECBF319413ED2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34638029461.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34638029461.webp', 'https://www.flickr.com/photos/zaragozaantigua/34638029461/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24685, 'Torreâ”œâ”‚n de la Zuda 1890', '"Torreâ”œâ”‚n del Palacio Real de la Azuda donde, al tomar Zaragoza, se aposentâ”œâ”‚ Alfonso el Batallador". Ilustraciâ”œâ”‚n de Ambrosio del Ruste, 1948, basada en una fotografâ”œآ،a de 1890. Fuente: "Conquista de Zaragoza por Don Alfonso I el Batallador", La Cadiera, 1948.', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65756000, -0.88163100, '0101000020E61000000C7904375236ECBF319413ED2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41407425642.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41407425642.webp', 'https://www.flickr.com/photos/zaragozaantigua/41407425642/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24686, 'Murallas romanas ca. 2005', 'Vista desde el torreâ”œâ”‚n de la Zuda de los restos de las murallas romanas, con la calle homâ”œâ”‚nima a la izquierda y la avenida de Câ”œآ®sar Augusto a la derecha. Se estâ”œأ­ procediendo a su restauraciâ”œâ”‚n, que incluye la retirada del pedestal con dos columnas que sostuvo la estatua de Câ”œآ®sar Augusto. Entre 2012 y 2013, esta zona se verâ”œأ­ modificada por el paso del tranvâ”œآ،a y la retirada de los arcos "Alegorâ”œآ،a de la Puerta de la Paz", entre las murallas y el Mercado Central. Al fondo, la câ”œâ•‘pula de la iglesia de Santiago el Mayor. Fuente: Archivo Antonio Tausiet.', 2005, 2005, 2005, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65718500, -0.88192100, '0101000020E6100000CEFA9463B238ECBFFC3559A31ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41597324550.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41597324550.webp', 'https://www.flickr.com/photos/zaragozaantigua/41597324550/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24687, 'Plaza de Huesca 1914', 'Foto: Serrano Sancho. "Hundimiento de una casa en Zaragoza. Estado en que quedâ”œâ”‚ la casa de la plaza de Huesca que se derrumbâ”œâ”‚ el miâ”œآ®rcoles â”œâ•‘ltimo", 28 de enero de 1914. Al fondo, la câ”œâ•‘pula de la torre de San Juan de los Panetes. Fuente: Diario ABC, 31-1-1914.', 1914, 1914, 1914, 'Anos 10', 'CASCO HISTâ”œأ´RICO', 41.65734300, -0.88091400, '0101000020E61000005AD5928E7230ECBF94A0BFD023D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43256261372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43256261372.webp', 'https://www.flickr.com/photos/zaragozaantigua/43256261372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24688, 'Avenida de Câ”œآ®sar Augusto 1999', 'La avenida de Câ”œآ®sar Augusto, en su tramo adyacente a las Murallas Romanas, entre el paseo de Echegaray y Caballero y el Mercado Central. A la izquierda, el Torreâ”œâ”‚n de la Zuda, y tras el lienzo de muralla, la iglesia de San Juan de los Panetes. Este entorno, olivos incluidos, serâ”œأ­ trocado en otro distinto con el paso de la nueva lâ”œآ،nea de tranvâ”œآ،a en 2013.', 1999, 1999, 1999, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65718500, -0.88192100, '0101000020E6100000CEFA9463B238ECBFFC3559A31ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50210619061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50210619061.webp', 'https://www.flickr.com/photos/zaragozaantigua/50210619061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24689, 'San Juan de los Panetes 1990', 'En el proyecto de rehabilitaciâ”œâ”‚n y embellecimiento de la plaza del Pilar, cuyas obras comenzaron tras las Fiestas del Pilar de 1990, estaba incluido el desmantelamiento del "Monumento a los hâ”œآ®roes y mâ”œأ­rtires de Zaragoza caâ”œآ،dos en la Cruzada de Liberaciâ”œâ”‚n 1936-1939", que serâ”œآ،a trasladado al cementerio catâ”œâ”‚lico de Torrero y sustituido por una fuente alusiva a la "Hispanidad". En la imagen, montaje de los andamios previo al desmontaje de este monumental cenotafio terminado en 1954, quince aâ”œâ–’os despuâ”œآ®s del oficial final de la guerra, como muestra de que el râ”œآ®gimen franquista no pasaba pâ”œأ­gina ni a sus orâ”œآ،genes ni a sus sâ”œآ،mbolos fundacionales, ni a la memoria de sus muertos. Este trâ”œأ­nsito edilicio apenas suscitâ”œâ”‚ polâ”œآ®mica o resiliencia social.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65725800, -0.88091200, '0101000020E61000002DEDD45C6E30ECBF6684B70721D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50374895517.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50374895517.webp', 'https://www.flickr.com/photos/zaragozaantigua/50374895517/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23749, 'Torre de Santa Engracia 1972', 'Torre de Santa Engracia era una finca del barrio rural de Movera que fue adquirida en 1970 por el Ayuntamiento, mediante permuta con la papelera La Montaâ”œâ–’anesa. El edificio responde a la tipologâ”œآ،a de las agrâ”œآ،colas torres de la periferia de Zaragoza, y estâ”œأ­ datada en el siglo XVII, cuando era propiedad del monasterio de Santa Engracia. En el siglo XIX fue desamortizada y muy modificada. Desde 2015 acoge a la Escuela Agrâ”œآ،cola Municipal Km 0.', 1972, 1972, 1972, 'Anos 70', NULL, 41.64234700, -0.80543500, '0101000020E610000067B8019F1FC6E9BF84D72E6D38D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15795238915.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15795238915.webp', 'https://www.flickr.com/photos/zaragozaantigua/15795238915/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24692, 'Torreâ”œâ”‚n de la Zuda c.1885', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 25 de la calle de Antonio Pâ”œآ®rez y centrada en el Torreâ”œâ”‚n de la Zuda reciâ”œآ®n restaurado y al que se ha incorporado una nueva cubierta a cuatro aguas proyectada por el arquitecto municipal Ricardo Magdalena. Este torreâ”œâ”‚n despunta de las instalaciones del antiguo palacio de la Castellanâ”œآ،a de Amposta de san Juan de Jerusalâ”œآ®n, desde unos pocos aâ”œâ–’os antes convertido en convento de las Madres Adoratrices, y con varias casas adosadas recayentes al lado de los pares de la calle de Antonio Pâ”œآ®rez. Tras el torreâ”œâ”‚n y a la izquierda aparece la iglesia de san Juan de los Panetes, y a la derecha la antigua torre inacabada de Santiago del templo del Pilar. Mâ”œأ­s al fondo, la barroca torre de la Seo.', 1885, 1885, 1885, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65755500, -0.88170600, '0101000020E6100000B5FB5580EF36ECBF202922C32AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52286836398.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52286836398.webp', 'https://www.flickr.com/photos/zaragozaantigua/52286836398/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24865, 'P.â”¬â•‘ del Ebro 1929', 'Imagen centrada en el antiguo paseo del Ebro, en la zona comprendida entre la calle del Fin y la iglesia de San Juan de los Panetes, al fondo, con el firme pendiente de embellecimiento, y notable trâ”œأ­fico de vehâ”œآ،culos tirados por caballerâ”œآ،a. Este tramo de la antigua lâ”œآ،nea tranviaria de Circunvalaciâ”œâ”‚n estaba suprimido desde 1925, cuando entrâ”œâ”‚ en servicio la lâ”œآ،nea del Ayuntamiento. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65750100, -0.87988100, '0101000020E610000097E5EB32FC27ECBF2D0B26FE28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35307218056.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35307218056.webp', 'https://www.flickr.com/photos/zaragozaantigua/35307218056/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25131, 'Calle del Fin aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste. Portada de la iglesia del antiguo Convento y colegio de San Nicolâ”œأ­s de Tolentino de los Agustinos, situado en la calle del Fin, uno de los postigos abiertos en la antigua muralla romana, que anteriormente fue conocido como "Postigo de Montaner", y luego "de la madera", por el trâ”œأ­fago de este material desde la ribera del Ebro hacia el interior de la ciudad. Este colegio fue abierto en 1605, y tenâ”œآ،a una pequeâ”œâ–’a iglesia que conectaba con el inmediato palacio de los Ayerbe, sus grandes financiadores. El colegio dio nombre ("Agustinos") a la calle que desde la plaza del Pilar conducâ”œآ،a a San Juan de los Panetes. Como todas las demâ”œأ­s construcciones de la zona, fueran palacios, colegios, o sencillas viviendas, fue arrasado cuando la plaza del Pilar fue retro-evolucionada del barroco, al nacional-catolicismo. En la imagen, la sencilla portada de la iglesia del colegio-convento. Destaca el escudo nobiliario en altorrelieve del barâ”œâ”‚n don Hugo de Urriâ”œآ®s y su mujer, doâ”œâ–’a Beatriz de Cardona y Requesens, patrocinadores del colegio. Por la izquierda se accedâ”œآ،a a la "puerta del Fin" que daba acceso al paseo de la ribera. Por la derecha, a la calle Agustinos. Fuente visual: Lâ”œأ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65722600, -0.87978600, '0101000020E610000026512FF83427ECBF5B0A48FB1FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18546963160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18546963160.webp', 'https://www.flickr.com/photos/zaragozaantigua/18546963160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25153, 'Torreâ”œâ”‚n de la Zuda aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste representando el torreâ”œâ”‚n de la Zuda, con la iglesia de San Juan de los Panetes a la derecha. Fuente: Lâ”œأ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65756000, -0.88160100, '0101000020E610000061DEE34C1336ECBF319413ED2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31627244013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31627244013.webp', 'https://www.flickr.com/photos/zaragozaantigua/31627244013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25406, 'Pasarela sobre el Ebro c.1945', 'Aguas arriba del puente de Piedra, estuvo en servicio esta pasarela peatonal sobre el Ebro, con taquillas en ambos mâ”œأ­rgenes, desde el 25 de febrero de 1941 hasta la inauguraciâ”œâ”‚n del puente de Santiago en 1967. Conocida como pasarela de Macanaz.', 1945, 1945, 1945, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65787500, -0.88078600, '0101000020E6100000FBC9181F662FECBF91ED7C3F35D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14899757335.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14899757335.webp', 'https://www.flickr.com/photos/zaragozaantigua/14899757335/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25419, 'Echegaray y Caballero 1956', 'Foto Josâ”œآ® Antonio Duce, 1956. Dâ”œآ،a de niebla en el Paseo de Echegaray y Caballero de Zaragoza, junto al Ebro, a la altura de la pasarela de Macanaz (al fondo). Fuente: www.rafaelcastillejo.com/zaraduce.htm', 1956, 1956, 1956, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65771500, -0.88075300, '0101000020E61000000D535BEA202FECBF598B4F0130D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15842183336.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15842183336.webp', 'https://www.flickr.com/photos/zaragozaantigua/15842183336/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25453, 'Pasarela de Macanaz 1950', 'Imagen estival centrada en la pasarela peatonal tendida sobre el râ”œآ،o Ebro en 1941, tambiâ”œآ®n conocida como de Macanaz, flanqueada por los escalonados descensos hacia los embarcaderos, y con una vista del antiguo colector de la Triperâ”œآ،a. La escena se ha capturado desde uno de los embarcaderos recreativos de la Margen Izquierda. El fondo edilicio viene determinado por el templo del Pilar con sus dos torres, como desde principios de siglo, la gran Hospederâ”œآ،a del Pilar de la Sociedad Angâ”œآ®lica del Sagrado Corazâ”œâ”‚n de Jesâ”œâ•‘s, el nuevo convento de las Hermanas Misioneras Eucarâ”œآ،sticas de Nazareth, adosado a la iglesia de San Juan de los Panetes, y el Grupo Escolar de Valentâ”œآ،n Zabala, sobre el que emerge el Torreâ”œâ”‚n de la Zuda. Fuente visual: AMZ', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65801400, -0.88160800, '0101000020E6100000008BFCFA2136ECBFB32781CD39D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39994558783.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39994558783.webp', 'https://www.flickr.com/photos/zaragozaantigua/39994558783/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25554, 'Puente de Santiago 2012', 'Obras para la segunda fase de la lâ”œآ،nea 1 del tranvâ”œآ،a, a su paso por el puente de Santiago. Al fondo, la margen izquierda del Ebro. Fuente: www.skyscrapercity.com/', 2012, 2012, 2012, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65821000, -0.88163300, '0101000020E61000003961C2685636ECBF38F3AB3940D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24825966856.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24825966856.webp', 'https://www.flickr.com/photos/zaragozaantigua/24825966856/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20894, 'Puerto fluvial siglo I', 'Maqueta del edificio de acceso del puerto fluvial de Caesaraugusta, siglo I. Al derribar las casas de la plaza de San Bruno en 1989 para construir las actuales viviendas de protecciâ”œâ”‚n oficial, se descubrieron los vestigios de una edificaciâ”œâ”‚n al nordeste del foro. Consta de una serie de vanos pertenecientes a una fachada de arquerâ”œآ،as orientada hacia el râ”œآ،o Ebro, por las que se alcanzaba un vestâ”œآ،bulo y desde â”œآ®ste una escalinata que comunicaba los muelles del puerto fluvial con la plaza del foro. Hoy es un museo visitable, en la plaza de San Bruno 8. Fuente: www.zaragoza.es/ciudad/museos/es/puerto', 50, NULL, 99, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65518900, -0.87460400, '0101000020E6100000D36C1E87C1FCEBBF77D9AF3BDDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19783359583.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19783359583.webp', 'https://www.flickr.com/photos/zaragozaantigua/19783359583/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20895, 'Puerto fluvial 1989', 'Estructura del puerto fluvial romano del siglo I en el entorno de la plaza de San Bruno de Zaragoza. Al fondo, la calle Arcedianos. Fuente: dp-foto.blogspot.com', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65518900, -0.87460400, '0101000020E6100000D36C1E87C1FCEBBF77D9AF3BDDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20082409184.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20082409184.webp', 'https://www.flickr.com/photos/zaragozaantigua/20082409184/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20903, 'Puerto fluvial siglo I', 'Recreaciâ”œâ”‚n infogrâ”œأ­fica del puerto fluvial de Caesaraugusta y su entorno junto al râ”œآ،o Ebro. A la derecha, el puente romano. Tras el gran edificio del puerto, el foro con su templo.', 50, NULL, 99, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65592200, -0.87462000, '0101000020E61000003EAE0D15E3FCEBBF0B5D8940F5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54170714151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54170714151.webp', 'https://www.flickr.com/photos/zaragozaantigua/54170714151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20925, 'Casa Diputados Reino 1539', 'Dibujo de Valentâ”œآ،n Carderera y Solano, del "patinejo" de la antigua Casa hospedaje de los Diputados del Reino de Aragâ”œâ”‚n, en la calle del General del Reino, un palacio del siglo XVI demolido parcialmente en 1863-64, cuando el patio fue desmontado, y completamente en la dâ”œآ®cada de los aâ”œâ–’os 40 del siglo XX, cuando el entorno de la Seo, como la calle de Palafox, fue "reordenado". Este palacio habâ”œآ،a sido adquirido como residencia de los Diputados del Reino que no vivâ”œآ،an en Zaragoza, mientras su estancia en la ciudad. El dibujo estâ”œأ­ tomado al natural, y datado en torno a 1860, poco antes del desmontaje del patio, aunque el autor parece situarlo en "1539", fecha de la talla del patio por Renâ”œآ® Trayanus, introduciendo para ambientar dos ficcionados personajes de esa â”œآ®poca. Cuatro columnas, cuatro pilastras, y algunos fragmentos del arquitrabe, en alabastro ensuciado, perduran en el Museo de Zaragoza, recompuestos desordenadamente. Fuente visual: ceres.mcu.es/', 1539, 1539, 1539, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65440600, -0.87472000, '0101000020E6100000210725CCB4FDEBBF31276893C3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22357296016.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22357296016.webp', 'https://www.flickr.com/photos/zaragozaantigua/22357296016/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20943, 'Monasterio de Santo Sepulcro 1855', '"Muralla romana y monasterio del Santo Sepulcro de Zaragoza." 28 de mayo 1855. Fuente visual: "Viaje artâ”œآ،stico por Aragâ”œâ”‚n de Valentâ”œآ،n Carderera", Josâ”œآ® Marâ”œآ،a Lanzarote Guiral, e Itziar Arana Cobos, IFC - Fundaciâ”œâ”‚n Lâ”œأ­zaro Galdiano, 2013.', 1855, 1855, 1855, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65424600, -0.87208200, '0101000020E6100000CAC4AD8218E8EBBFF8C43A55BED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14868828807.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14868828807.webp', 'https://www.flickr.com/photos/zaragozaantigua/14868828807/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20985, 'Puente de Tablas 1803', '"Plan y elevaciâ”œâ”‚n general y perfiles por mayor del puente de madera proyectado sobre el râ”œآ،o Ebro en el mismo sitio que estaba el antiguo para paso de la carretera real de Madrid a Barcelona", Fernando Martâ”œآ،nez Corcâ”œآ،n, Zaragoza, 13 de junio de 1803. La avenida del Ebro del 10 de junio de 1801 daâ”œâ–’â”œâ”‚ por enâ”œآ®sima vez el Puente de Tablas de Zaragoza, que habâ”œآ،a sido reconstruido tras la riada del 23 de junio de 1775. En 1803 se proyecta de nuevo, aprobâ”œأ­ndose la obra al aâ”œâ–’o siguiente, aunque no se llevâ”œâ”‚ a cabo. En 1895 se inaugurâ”œâ”‚ en sus inmediaciones el Puente del Pilar o de Hierro. Fuente visual: Fondo del Intendente. Secciâ”œâ”‚n de Obras Municipales. Diputaciâ”œâ”‚n Provincial de Zaragoza.', 1803, 1803, 1803, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65580700, -0.87212500, '0101000020E61000009CC420B072E8EBBF73BED87BF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24088066161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24088066161.webp', 'https://www.flickr.com/photos/zaragozaantigua/24088066161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21057, 'Vista desde Altabâ”œأ­s c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y Câ”œآ،a. 1872-1879. Vista general de la ribera derecha, desde la Iglesia de Altabâ”œأ­s, trozo 1.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65567900, -0.87385200, '0101000020E6100000056A317898F6EBBF45D61A4AEDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14865823302.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14865823302.webp', 'https://www.flickr.com/photos/zaragozaantigua/14865823302/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21105, 'San Nicolâ”œأ­s 1889', '"Saragosse. â”œأ«glise St-Nicolas". Fuente: J. Lâ”œآ®vy et Cie, en "Zaragoza en la mirada ajena", Cortes de Aragâ”œâ”‚n, 2012.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65402100, -0.87257100, '0101000020E61000003A048E041AECEBBFD8F2CAF5B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22104618133.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22104618133.webp', 'https://www.flickr.com/photos/zaragozaantigua/22104618133/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21170, 'Puente de Hierro 1894', 'Para aligerar al puente de Piedra de una parte de su trâ”œأ­nsito, y dar nuevo paso a la carretera de Madrid a Francia por la Junquera, en 1877 fue aprobada la construcciâ”œâ”‚n de un nuevo puente sobre el Ebro. Diseâ”œâ–’ado por el ingeniero Antonio Fernâ”œأ­ndez de Navarrete, y tras un dilatado proceso de construcciâ”œâ”‚n que comenzâ”œâ”‚ en 1887, fue inaugurado en octubre de 1895 con el nombre de "puente de Nuestra Seâ”œâ–’ora del Pilar". En la imagen, captura de las obras de este nuevo puente de Hierro, con el Pilar y el paseo del Ebro a la izquierda, el puente de Piedra detrâ”œأ­s, y la arboleda y lavaderos de la calle de Jesâ”œâ•‘s a la derecha, en la margen izquierda. Fuente visual: Archivo Coyne, en "Zaragoza. Dos milenios de agua", Carlos Blâ”œأ­zquez, 2006.', 1894, 1894, 1894, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65554800, -0.87099000, '0101000020E6100000C993A46B26DFEBBFA77A32FFE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29292358483.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29292358483.webp', 'https://www.flickr.com/photos/zaragozaantigua/29292358483/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21195, 'Paseo del Ebro c.1893', 'Imagen capturada posiblemente desde la estructura en construcciâ”œâ”‚n del nuevo puente sobre el râ”œآ،o Ebro que con la denominaciâ”œâ”‚n de puente de Nâ”¬آ¬ Sâ”¬آ¬ del Pilar, fue iniciado en 1887 e inaugurado en 1895. Con el fondo edilicio del barrio de La Seo y el paseo del Ebro, destaca en primer tâ”œآ®rmino y a la izquierda, el estribo sureâ”œâ–’o del antiguo puente de Tablas o Madera. Tras â”œآ®l, el emboque con la calle del Conde de Alperche. Hacia la derecha, del caserâ”œآ،o emerge el cimborrio y la torre de la Seo, seguido a continuaciâ”œâ”‚n por el Palacio Arzobispal y el Seminario Conciliar de San Valero y de San Braulio.', 1893, 1893, 1893, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65539000, -0.87388500, '0101000020E6100000F4E0EEACDDF6EBBF0E10CCD1E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50639375491.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50639375491.webp', 'https://www.flickr.com/photos/zaragozaantigua/50639375491/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21419, 'Convento de Jesâ”œâ•‘s c.1910', 'Imagen centrada en el puente nuevo, de Nâ”¬آ¬ Sâ”¬آ¬ del Pilar, o de Hierro, capturada desde la margen derecha del Ebro. Al fondo, la torre del antiguo convento franciscano de Nâ”¬آ¬ Sâ”¬آ¬ de Jesâ”œâ•‘s. En beneficio de todos, hemos volteado horizontalmente la imagen original. Fuente visual: Arxiu Nacional de Catalunya', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œأ´RICO', 41.65562800, -0.87081800, '0101000020E61000008194D8B5BDDDEBBFC32B499EEBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30950627624.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30950627624.webp', 'https://www.flickr.com/photos/zaragozaantigua/30950627624/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21475, 'Calle Palafox 1929', 'Imagen de la calle de Palafox desde la calle del Chantre, tras el derribo del antiguo edificio de la Aduana Vieja, o Casa de los Diputados del Reino. A la izquierda, el antiguo palacio de los Lazâ”œأ­n. Al fondo, la catedral de la Seo. Justo enfrente, las casas del cabildo que fueran del Arcediano de Belchite, con la fachada que daba a la plazuela de la Aduana, desde donde se accedâ”œآ،a al derribado edificio. Esta demoliciâ”œâ”‚n permitiâ”œâ”‚ realinear ese lado de la calle Palafox, retranqueâ”œأ­ndola y haciâ”œآ®ndola mâ”œأ­s ancha, y sobre el solar se construirâ”œأ­ inmediatamente el Grupo Escolar Marcelino Lâ”œâ”‚pez Ornat. Fuente visual: Archivo Josâ”œآ® Galiay (DARA-AHPZ).', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65403600, -0.87439400, '0101000020E61000002B323A2009FBEBBF0D349F73B7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14700854338.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14700854338.webp', 'https://www.flickr.com/photos/zaragozaantigua/14700854338/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21477, 'Calle Sepulcro 1925', 'Foto Roisin, 1925. Toma de la torre de la Seo desde la confluencia de la calle del Sepulcro con el callejâ”œâ”‚n de Ezmir, con su palacio homâ”œâ”‚nimo, de Esmir o de los marqueses de Almonacid, a la derecha.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65464000, -0.87397100, '0101000020E610000098E0D40792F7EBBFA453573ECBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14798514377.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14798514377.webp', 'https://www.flickr.com/photos/zaragozaantigua/14798514377/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21480, 'Aduana Vieja 1929', 'Imagen de la Plaza o Plazuela de la Aduana, a la izquierda, y la portada de ingreso a la "Aduana Vieja", antigua Casa de hospedaje de la Diputaciâ”œâ”‚n del Reino para diputados foranos de Zaragoza. La callecita de la derecha, antigua del "General del Reino", luego "Palafox", conectaba esta plaza con la Plaza del Reino, y la calle del Chantre, al fondo de la imagen. A la derecha, fuera de plano, el Palacio del Marquâ”œآ®s de Lazâ”œأ­n. Esta imagen estâ”œأ­ datada oficialmente en 1949, aunque es improbable que esa sea la fecha: en 1929 se acometieron obras para una nueva alineaciâ”œâ”‚n de la calle Palafox (ensanchamiento), y de un aâ”œâ–’o despuâ”œآ®s (1930) es el proyecto de Marcelino Carquâ”œآ® para el nuevo "Grupo Escolar Marcelino Lâ”œâ”‚pez Ornat", escuela municipal levantada en la esquina de Palafox con la calle del Chantre (luego San Vicente de Paâ”œâ•‘l), ocupando todo el espacio del muro de la imagen, el solar del antigua Aduana, y la mayor parte de la plazuela. La imagen parece realizada, por todo ello, en el tiempo de otras imâ”œأ­genes de esta zona (Julio Requejo, Miguel Faci, Antâ”œâ”‚nio Passaporte). Fuente visual: Archivo Mora. Ayuntamiento de Zaragoza. "Antigua Aduana. Calle de Palafox".', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65399600, -0.87433500, '0101000020E6100000EDF0D7648DFAEBBF7FDB1324B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14957567152.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14957567152.webp', 'https://www.flickr.com/photos/zaragozaantigua/14957567152/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21481, 'Antigua Aduana 1929', '"Portada Antigua Aduana. Calle de Palafox". Antigua Casa de los Diputados (foranos) del Reino, frente al Palacio de Palafox, que queda a su derecha. Fuente visual: Ayuntamiento de Zaragoza/Archivo Mora.', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65402800, -0.87437300, '0101000020E61000004D2CF015DDFAEBBF8A558330B7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14958019132.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14958019132.webp', 'https://www.flickr.com/photos/zaragozaantigua/14958019132/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21538, 'Paseo del Ebro 1922', 'Dibujo de Dâ”œآ،az Domâ”œآ،nguez del paseo del Ebro a la altura del Palacio Arzobispal (derecha). Al fondo, la Seo. Fuente: La Cadiera 114, 1957.', 1922, 1922, 1922, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65552600, -0.87444400, '0101000020E61000009CDEC5FB71FBEBBFBFD6A546E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19870797930.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19870797930.webp', 'https://www.flickr.com/photos/zaragozaantigua/19870797930/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21543, 'Soto del Caâ”œâ–’ar 1925', 'Zaragoza desde el soto del Caâ”œâ–’ar, Lucien Roisin, 1925. Vista de Zaragoza desde el soto del Caâ”œâ–’ar, con el puente del Pilar o de Hierro al fondo. Se pueden ver las torres de San Nicolâ”œأ­s, la Seo (bajo la cual, los restos del estribo derecho del puente de Tablas) y el Pilar. Fuente: "Zaragoza, aâ”œâ–’os veinte. 81 fotografâ”œآ،as de Roisin (1925-1931)", Instituciâ”œâ”‚n Fernando el Catâ”œâ”‚lico, 2014.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65567700, -0.86822200, '0101000020E6100000E65DF58079C8EBBFA4DE5339EDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20095777311.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20095777311.webp', 'https://www.flickr.com/photos/zaragozaantigua/20095777311/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21558, 'Aduana Vieja 1925', 'Miguel Faci Abad. 1920-1925. "Zaragoza. Antiguo edificio de la Aduana, en la plaza del Reino" (sic). Imagen de la Plaza o Plazuela de la Aduana, a la izquierda, y la portada de ingreso a la "Aduana Vieja", antigua Casa de hospedaje de la Diputaciâ”œâ”‚n del Reino para diputados foranos de Zaragoza, y luego pluriempleada como almacâ”œآ®n, retâ”œآ®n militar, y aun de bomberos. La callecita de la derecha, antigua del "General del Reino", luego "Palafox", conectaba esta plaza con la Plaza del Reino, y la calle del Chantre, al fondo de la imagen. A la derecha, fuera de plano, el Palacio del Marquâ”œآ®s de Lazâ”œأ­n. Las caballerâ”œآ،as son dirigidas hacia la doble plaza de San Bruno. Unos pocos aâ”œâ–’os despuâ”œآ®s (1929-30) este edificio serâ”œأ­ derribado para ensanchar la calle, y construir sobre su solar el nuevo "Grupo Escolar Marcelino Lâ”œâ”‚pez Ornat". Fuente visual: Fuente visual: "Miguel y Gabriel Faci. Fotâ”œâ”‚grafos fundadores de la Real Sociedad Fotogrâ”œأ­fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaciâ”œâ”‚n Provincial de Zaragoza, 1999.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65440600, -0.87472000, '0101000020E6100000210725CCB4FDEBBF31276893C3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21768175313.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21768175313.webp', 'https://www.flickr.com/photos/zaragozaantigua/21768175313/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21570, 'Calle de Pallaruelo, c.1929', '"Zaragoza. Calle del Pallazuelo." (sic) La antigua e irregular calle de Pallaruelo, en el barrio del Boterâ”œâ”‚n, venâ”œآ،a a ser la natural continuidad de la calle de Gavâ”œآ،n, pasada la del Sepulcro, si bien terminaba en un fondo de saco sin conexiâ”œâ”‚n directa con el paseo del Ebro. Para salir de ella habâ”œآ،a que tomar la calleja del Retiro y enlazar con la del Garro para desembocar en la del Conde Alperche, que sâ”œآ، tenâ”œآ،a salida a la ribera. La otra opciâ”œâ”‚n era volverse por donde se habâ”œآ،a entrado. El nombre de Pallaruelo, antes Bual, le fue dado por el paisano que, enriquecido tras la batalla de Zaragoza de 1710, mediante el despojo de cuanto cadâ”œأ­ver se le puso por delante, pudo comprarse una casa en esta câ”œآ®ntrica zona de la ciudad. Esta calle perdurâ”œâ”‚, en forma y fondo, hasta que la remodelaciâ”œâ”‚n de la zona supuso su alineamiento ortogonal y apertura por Echegaray y Caballero. Entonces, fue redenominada "Boterâ”œâ”‚n". En la imagen, vista de la calle desde su entrada por la del Sepulcro. Al fondo, hacia la izquierda, el fondo de saco de su final, y la conexiâ”œâ”‚n con la calle del Retiro. Fuente visual: Archivo Juan Mora Insa (DARA-AHPZ).', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65444700, -0.87320800, '0101000020E6100000D06053E751F1EBBF8FFB56EBC4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23785233172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23785233172.webp', 'https://www.flickr.com/photos/zaragozaantigua/23785233172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21572, 'Calle de Monserrate c.1929', '"Zaragoza. Calle de Monserrate." La antigua calle de Monserrate recibâ”œآ،a ese nombre por el importante postigo del mismo nombre que se abrâ”œآ،a a la ribera y daba conexiâ”œâ”‚n con la calle del Sepulcro. De traza irregular, era "paralela" a la calle de Pallaruelo, y presentaba un peculiar ensanchamiento denominado "del Lobo". Esta calle perdurâ”œâ”‚ hasta que la reordenaciâ”œâ”‚n urbanâ”œآ،stica de la zona supuso su desapariciâ”œâ”‚n. En la imagen, vista de la calle desde su estrecha entrada por la del Sepulcro. Fuente visual: Archivo Juan Mora Insa (DARA-AHPZ).', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65426200, -0.87295000, '0101000020E6100000E561A1D634EFEBBFFE8172DBBED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23867860796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23867860796.webp', 'https://www.flickr.com/photos/zaragozaantigua/23867860796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21602, 'Puente de Hierro c.1920', 'Imagen del puente sobre el râ”œآ،o Ebro levantado en 1895 donde, aproximadamente, estuviera el antiguo puente de Tablas. Fue realizado en materiales mucho mâ”œأ­s perdurables que las antiguas versiones en madera, siempre a merced de los desmadres de un râ”œآ،o natural. Como no podâ”œآ،a ser de otra forma en esta ciudad, recibiâ”œâ”‚ la corporativa denominaciâ”œâ”‚n de "Nâ”¬آ¬ Sâ”¬آ¬ del Pilar", si bien el comâ”œâ•‘n se refiere a â”œآ®l con mâ”œأ­s utilitarismo: es el puente "de Hierro", para diferenciarlo del "de Piedra" caracoleâ”œâ–’a. En la imagen, capturada desde la margen izquierda, el puente queda contrastado por el modesto fondo de la antigua parroquia de San Nicolâ”œأ­s (con detalle de la sede de la Cruz Roja), y la barriada de las Taâ”œâ–’erâ”œآ،as. En el centro, despuntan la torre de San Nicolâ”œأ­s y, por un capricho visual, la de la Magdalena. Fuente visual: Archivo Coyne, en "Zaragoza dos milenios de agua", Carlos Blâ”œأ­zquez.', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65554800, -0.87099000, '0101000020E6100000C993A46B26DFEBBFA77A32FFE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26255917471.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26255917471.webp', 'https://www.flickr.com/photos/zaragozaantigua/26255917471/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21632, 'Calle Sepulcro 1922', 'Dibujo de Dâ”œآ،az Domâ”œآ،nguez de la calle del Sepulcro en 1922, con la torre de la Seo al fondo y el palacio de Esmir a la derecha. Fuente: Revista La Cadiera.', 1922, 1922, 1922, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65471400, -0.87396000, '0101000020E61000009D6340F67AF7EBBFDE1D19ABCDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42289443685.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42289443685.webp', 'https://www.flickr.com/photos/zaragozaantigua/42289443685/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21913, 'Calle del Sepulcro 1932', 'Imagen capturada en el tramo de la calle del Sepulcro que se ensanchaba de forma notable junto a la casa de los Esmir, cuya fachada queda a la derecha. Al fondo emerge la gran torre barroca de la Seo.', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65496600, -0.87414200, '0101000020E6100000C8EBC1A4F8F8EBBFF8FE06EDD5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52507636009.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52507636009.webp', 'https://www.flickr.com/photos/zaragozaantigua/52507636009/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21950, 'Calle de Arcedianos 1949', 'Irrepetible captura de la antigua calle de Arcedianos, cuando aâ”œâ•‘n era reflejo de la abigarrada calleja que conectaba la doble plaza de San Bruno con la calle del Chantre. La calle del Chantre (a la derecha) ya no existâ”œآ،a, pues habâ”œآ،a sido sustituida por un moderno vial para vehâ”œآ،culos (San Vicente de Paâ”œâ•‘l), mas aâ”œâ•‘n quedaban en pie los edificios de la calle, con trazas desde del siglo XVI en adelante, que culminaban, casi tocando a la sacristâ”œآ،a de la Seo (al fondo), en la antigua Hospederâ”œآ،a de la Cartuja de la Concepciâ”œâ”‚n, cuya imagen de San Bruno, en una hornacina sobre la puerta, daba nombre a la irregular plaza del mismo nombre. La desconsideraciâ”œâ”‚n para con el patrimonio que no fue afectado por los dos sitios de 1808-1809, convirtiâ”œâ”‚ en potencial carne de derribo a todo aquel edificio que no tuviera incrustada una bala francesa (o espaâ”œâ–’ola, quâ”œآ® mâ”œأ­s da), como es el caso. Nada queda de esta vista, salvo la Seo, al fondo, y una plaza de San Bruno endurecida, recrecida y convertida en ocasional mercado y escenario de conciertos. Fuente visual: Archivo Municipal, Archivo Mora, 1949.', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65461300, -0.87459300, '0101000020E6100000D8EF8975AAFCEBBFAA44D95BCAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18557291260.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18557291260.webp', 'https://www.flickr.com/photos/zaragozaantigua/18557291260/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21985, 'Calle Sepulcro C.1949', 'Dibujo de Esteban representando la calle del Sepulcro, con el palacio de Esmir a la derecha y la torre de la Seo al fondo. Fuente: www.facebook.com/photo.php?fbid=1156035214477222&set=...', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65491800, -0.87462500, '0101000020E6100000B0726891EDFCEBBFE7C75F5AD4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29122370861.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29122370861.webp', 'https://www.flickr.com/photos/zaragozaantigua/29122370861/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22038, 'Muralla indâ”œآ،gena 1990', 'Muralla indâ”œآ،gena de Salduie, aparecida en 1990 en la excavaciâ”œâ”‚n de la calle del Sepulcro 1 -15, solar del antiguo palacio de Esmir, en el entorno de la plaza de San Bruno correspondiente a los aledaâ”œâ–’os noroccidentales de la plaza porticada identificada con el posterior foro comercial romano. Se conservan 34 metros de longitud y 1 metro de altura. Es de yeso alabastrino y tiene una orientaciâ”œâ”‚n este-oeste, paralela al curso del Ebro, del que dista ocho metros. Forma parte del lienzo norte de la muralla de Salduie, resultando uno de los hallazgos mâ”œأ­s importantes de la arqueologâ”œآ،a zaragozana. Al fondo, el palacio Arzobispal. Fuente visual: Zaragoza. prehistoria y arqueologâ”œآ،a. Ayuntamiento de Zaragoza, 1991.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65525400, -0.87461400, '0101000020E6100000B6F5D37FD6FCEBBF5E49F25CDFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14971051956.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14971051956.webp', 'https://www.flickr.com/photos/zaragozaantigua/14971051956/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22067, 'Maderas Nicolâ”œأ­s Hermanos 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Puente del Pilar." El negocio de maderas para la construcciâ”œâ”‚n de la empresa "Nicolâ”œأ­s Hermanos" arranca en la dâ”œآ®cada de los 80 del XIX. En 1900 construyeron sus propios locales en el Paseo del Ebro nâ”¬â•‘ 70 (Barrio de las Tenerâ”œآ،as), en un solar contiguo al nuevo puente de hierro del Pilar, que inauguraron en 1901. La nueva planta se componâ”œآ،a de dos naves y un notable edificio destinado a vivienda y oficinas. El cartel anunciador informaba "Maderas y serrerâ”œآ،a Nicolâ”œأ­s Hermanos". Allâ”œآ، estuvieron hasta que la fâ”œأ­brica fue piqueteada. Al fondo, el puente de Hierro. En el suelo, los raâ”œآ،les de la lâ”œآ،nea de tranvâ”œآ،a del Gâ”œأ­llego, hacia el puente, con la derivaciâ”œâ”‚n hacia la izquierda de la Lâ”œآ،nea de Circunvalaciâ”œâ”‚n. En primer plano, el edificio central de la fâ”œأ­brica, muy prâ”œâ”‚ximo a la plaza de Tenerâ”œآ،as.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65379500, -0.87158900, '0101000020E6100000FEB4519D0EE4EBBFE8A4F78DAFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15085373488.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15085373488.webp', 'https://www.flickr.com/photos/zaragozaantigua/15085373488/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22077, 'San Nicolâ”œأ­s aâ”œâ–’os 50', 'Archivo Municipal. Gerardo Sancho Ramo. Aâ”œâ–’os 50. Plazuela de San Nicolâ”œأ­s, con la iglesia de San Nicolâ”œأ­s de Bari, en la calle del Sepulcro.', 1950, 1950, 1959, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65402100, -0.87257100, '0101000020E61000003A048E041AECEBBFD8F2CAF5B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15688929496.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15688929496.webp', 'https://www.flickr.com/photos/zaragozaantigua/15688929496/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22084, 'Plazuela de San Nicolâ”œأ­s c.1950', 'Plazuela de San Nicolâ”œأ­s con imagen de la fachada y torrecilla campanario de la barroca iglesia de San Nicolâ”œأ­s de Bari, junto al convento de las Madres Comendadoras Canonesas Regulares del Santo Sepulcro. Un rincâ”œâ”‚n de la antigua Zaragoza que perdura, salvo las viviendas de la izquierda, desaparecidas en reformas posteriores. Fuente visual: Archivo Coyne, AHPZ.', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65402100, -0.87257100, '0101000020E61000003A048E041AECEBBFD8F2CAF5B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16331827354.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16331827354.webp', 'https://www.flickr.com/photos/zaragozaantigua/16331827354/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22227, 'Râ”œآ،o Ebro 1954', 'Imagen capturada desde el Puente de Hierro y centrada en la inmediata ribera de la margen derecha del râ”œآ،o Ebro. En primer tâ”œآ®rmino destacan los restos del antiguo estribo sur del Puente de Tablas (desaparecido definitivamente durante la riada de 1801). Por encima emerge la barroca torre y el cimborrio mudâ”œآ®jar de la catedral del Salvador en su Epifanâ”œآ،a. En el centro de la escena, los dos torreones del Palacio Arzobispal, la estructura en obras de la nueva Casa Consistorial, y el templo del Pilar, con las dos torres ribereâ”œâ–’as en construcciâ”œâ”‚n. Hacia la derecha, el Puente de Piedra, sobre el que transita un tranvâ”œآ،a de la serie de los 40 en servicio en la lâ”œآ،nea 9. Gâ”œأ­llego, antes de ser sustituida por una nueva lâ”œآ،nea de trolebuses; a su izquierda, una composiciâ”œâ”‚n motor+remolque de la serie 100 de la tranviaria lâ”œآ،nea 10. Academia.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65595200, -0.87218900, '0101000020E61000004BCADDE7F8E8EBBF76DF313CF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49300702786.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49300702786.webp', 'https://www.flickr.com/photos/zaragozaantigua/49300702786/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22300, 'Arco del Deâ”œأ­n 1968', 'Archivo Municipal. Gerardo Sancho Ramo. Abril 1968. Aprovechando el derribo de un edificio anexo a las dependencias arzobispales de la calle Deâ”œأ­n, y al que tambiâ”œآ®n se podâ”œآ،a acceder por un aâ”œآ®reo pasaje, se tomâ”œâ”‚ esta imagen del Arco y Casa del Deâ”œأ­n de la Seo (restaurados la dâ”œآ®cada anterior) desde una perspectiva interesante. Al fondo, la esquina de la calle de Palafox.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65491800, -0.87462500, '0101000020E6100000B0726891EDFCEBBFE7C75F5AD4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15546947427.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15546947427.webp', 'https://www.flickr.com/photos/zaragozaantigua/15546947427/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22420, 'Coso Bajo 1967', 'Imagen capturada en el tramo final del Coso Bajo, junto a las Tenerâ”œآ،as, durante el paso de la banda de mâ”œâ•‘sica de la 8.â”¬آ¬ Divisiâ”œâ”‚n de Infanterâ”œآ،a del ejâ”œآ®rcito de los Estados Unidos de Amâ”œآ®rica del Norte, que participarâ”œآ،a en las Fiestas de Primavera de ese aâ”œâ–’o. Esta unidad militar, estacionada habitualmente en territorio de la Repâ”œâ•‘blica Federal de Alemania, recayâ”œâ”‚ temporalmente en Zaragoza por su participaciâ”œâ”‚n en las maniobras conjuntas con el ejâ”œآ®rcito espaâ”œâ–’ol denominadas Pathfinder Express, desarrolladas en diversas localizaciones de Zaragoza, Calatayud y Daroca, y en las que la base aâ”œآ®rea de Valenzuela tuvo un papel fundamental. La Pathfinder Express se basaba en el supuesto de que la naciâ”œâ”‚n imaginaria de "Iberia" era invadida por una "Repâ”œâ•‘blica Agresora", de forma que el Gobierno de Iberia pedâ”œآ،a apoyo militar al Gobierno de "Iberia occidental", que se lo concedâ”œآ،a para repeler la agresiâ”œâ”‚n. El General Mayor Cassidy, comandante de la 8.â”¬آ¬ Divisiâ”œâ”‚n de infanterâ”œآ،a norteamericana participante en esa operaciâ”œâ”‚n, habâ”œآ،a desembarcado en 1944 en Normandâ”œآ،a como miembro de la 101.â”¬آ¬ divisiâ”œâ”‚n aerotransportada para luchar contra los nazis. El Capitâ”œأ­n General Muâ”œâ–’oz Grandes, asistente a estas maniobras en su calidad de vicepresidente del Gobierno espaâ”œâ–’ol, lucâ”œآ،a la Cruz de Caballero de la Cruz de Hierro con hojas de roble que le fue concedida personalmente por Adolf Hitler por comandar la Divisiâ”œâ”‚n Azul partâ”œآ،cipe de la agresiâ”œâ”‚n nazi a la URSS. En la imagen, a la izquierda, las traseras del Real Monasterio de Comendadoras Canonesas de la Orden Militar y Pontificia del Santo Sepulcro, integrado en un paâ”œâ–’o de las antiguas murallas de piedra de la ciudad. Sobre el firme, rieles de la antigua lâ”œآ،nea tranviaria 12 Barrio de Jesâ”œâ•‘s. Fuente visual: Jarke/Jaria, AMZ.', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65413700, -0.87187000, '0101000020E6100000F5A10BEA5BE6EBBF410DDFC2BAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26741753949.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26741753949.webp', 'https://www.flickr.com/photos/zaragozaantigua/26741753949/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22514, 'Puente de Hierro c.1965', 'Imagen capturada junto al cuartel de automovilismo de las Tenerâ”œآ،as. Al fondo, el puente de Nâ”¬آ¬ Sâ”¬آ¬ del Pilar, sobre el que se dispone a cruzar una motocicleta. Destaca el tendido tranviario tambiâ”œآ®n utilizado por trolebuses.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65417200, -0.87151400, '0101000020E61000005532005471E3EBBFBEFA78E8BBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51356559226.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51356559226.webp', 'https://www.flickr.com/photos/zaragozaantigua/51356559226/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22680, 'Puente de Hierro 1970', 'Imagen capturada desde el Puente de Hierro durante las obras de restauraciâ”œâ”‚n de su desgastado firme, que aquâ”œآ، se muestra transparente y produce vertiginosas sensaciones, tal que si de un felino caminando sobre un cristal se tratase. Al fondo, entre, y sobre, la metâ”œأ­lica barandilla, las instalaciones fabriles de una familiar e influyente empresa local de colchones, en el barrio de Jesâ”œâ•‘s, unos aâ”œâ–’os antes de trasladarse a la carretera de Logroâ”œâ–’o. Bajo del puente, un Ebro de aguas tranquilas fluye presocrâ”œأ­ticamente hacia el Mediterrâ”œأ­neo. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal Zaragoza. Referencia: ES. 50297. AM 04.01.02.13 Sobre 118267', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65628200, -0.87028900, '0101000020E61000008331225168D9EBBF0B7A6F0C01D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26311542452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26311542452.webp', 'https://www.flickr.com/photos/zaragozaantigua/26311542452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22725, 'Puente de Hierro 1972', 'Foto centrada en la unidad 201 de la lâ”œآ،nea 35 de los autobuses urbanos, "Verâ”œâ”‚nica-Arrabal". Estâ”œأ­ circulando por el puente del Pilar o de Hierro, en direcciâ”œâ”‚n a la margen izquierda. Fuente: Colecciâ”œâ”‚n Daniel Andrâ”œآ®s.', 1972, 1972, 1972, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65562800, -0.87081800, '0101000020E61000008194D8B5BDDDEBBFC32B499EEBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30552364404.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30552364404.webp', 'https://www.flickr.com/photos/zaragozaantigua/30552364404/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22793, 'Calle del Sepulcro c.1978', 'Vista de los grandes solares resultantes de los derribos realizados la dâ”œآ®cada anterior en el entorno de la calle del Sepulcro, del palacio Arzobispal (a la derecha, con la fachada en reformas) y de la pequeâ”œâ–’a plaza de San Bruno (a la izquierda, inmediata a la Seo). El solar de la derecha es el de la antigua y gran casa de los Esmir, y el de la izquierda el que en tiempos albergara el hospicio de la Cartuja de la Concepciâ”œâ”‚n y la carnicerâ”œآ،a del Cabildo. La imagen ha sido capturada posiblemente desde la altura del nâ”¬â•‘ 49 de la calle de San Vicente de Paâ”œâ•‘l. De fondo escâ”œآ®nico, la iglesia metropolitana del Salvador en su Epifanâ”œآ،a. Tras ella, despuntan hitos verticales como la câ”œâ•‘pula del Banco Zaragozano, la torre de San Gil, el Edificio Ebrosa, la torre de San Pablo y las de Santa Isabel. A la derecha, la torre de Nuestra Seâ”œâ–’ora del Pilar del homâ”œâ”‚nimo templo.', 1978, 1978, 1978, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65509600, -0.87481700, '0101000020E6100000BE839F3880FEEBBFC6DE8B2FDAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41676464952.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41676464952.webp', 'https://www.flickr.com/photos/zaragozaantigua/41676464952/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23003, 'Râ”œآ،o Ebro aâ”œâ–’os 90', 'Vista del râ”œآ،o Ebro a su paso por Zaragoza. En primer tâ”œآ®rmino, puente de Piedra y torre noreste del Pilar. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œآ® Marâ”œآ،a Sanz Gonzâ”œأ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1990, 1990, 1999, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65639800, -0.87268500, '0101000020E61000005BB6D61709EDEBBF759483D904D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27385635046.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27385635046.webp', 'https://www.flickr.com/photos/zaragozaantigua/27385635046/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23209, 'Puente de Hierro 2010', 'Foto: Carlos Moncâ”œآ،n. Mayo de 2010. Obras de restauraciâ”œâ”‚n y cambio de color del puente de Nuestra Seâ”œâ–’ora del Pilar, vulgo de Hierro. El "verde tradicional" que habâ”œآ،a sustituido en los aâ”œâ–’os setenta al gris, se trocâ”œâ”‚ por el azul y blanco, tras una consulta populista. Fuente: Heraldo de Aragâ”œâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65577200, -0.87071100, '0101000020E6100000008FA850DDDCEBBFF6D03E56F0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33225069960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33225069960.webp', 'https://www.flickr.com/photos/zaragozaantigua/33225069960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23437, 'Aduana Vieja 1922', 'Fachada del edificio donde estaba ubicado el primer retâ”œآ®n de Bomberos de Zaragoza, en la plazuela de la Aduana, junto a la calle de Palafox. La antigua Casa de los Diputados del Reino fue construida en el siglo XVI por Marcos de Maâ”œâ–’aria, y comprada en 1590 para estancia temporal en Zaragoza de los diputados no residentes. En el siglo XIX, ya propiedad del Ayuntamiento pasâ”œâ”‚ a denominarse Aduana Vieja, con usos varios, incluyendo alojamiento de un retâ”œآ®n militar, depâ”œâ”‚sito municipal, câ”œأ­rcel y cuartelillo, y retâ”œآ®n de bomberos. Un acta municipal de 1862 indica que el edificio estâ”œأ­ en ruina, y al aâ”œâ–’o siguiente el retâ”œآ®n de bomberos es desalojado. En 1863-64 el edificio es parcialmente derribado, y el resto perdura hasta la reordenaciâ”œâ”‚n de la calle a finales de la dâ”œآ®cada de los aâ”œâ–’os 20, y principios de la de los 30. Quedan restos del patio interior, recompuestos en desordenado tetris, en el Museo de Zaragoza. Fuente visual: Julio Requejo.', 1922, 1922, 1922, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65399100, -0.87437800, '0101000020E6100000BFF04A92E7FAEBBF6D7022FAB5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14771318117.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14771318117.webp', 'https://www.flickr.com/photos/zaragozaantigua/14771318117/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23445, 'Plaza del Reino 1930', 'Ayuntamiento de Zaragoza/Archivo Mora, 1930 Sede de la Real Sociedad Econâ”œâ”‚mica Aragonesa de Amigos del Paâ”œآ،s, en la plaza del Reino 5 de Zaragoza. De 1876 a 1905, sede tambiâ”œآ®n de la Caja de Ahorros de Zaragoza. En esa misma plaza se encontraban ademâ”œأ­s la Real Academia de Nobles y bellas Artes de San Luis (1792) y el Seminario de Pobres de San Francisco de Paula (1886).', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65401300, -0.87439500, '0101000020E6100000422619390BFBEBBF5514AFB2B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14982089722.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14982089722.webp', 'https://www.flickr.com/photos/zaragozaantigua/14982089722/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23472, 'Aduana Vieja aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste identificada como "palacio de Palafox". Muestra el palacio de la Aduana Vieja, en la plazuela de la Aduana. A la derecha, antigua calle del General del Reino, luego Palafox. Fuente: Lâ”œأ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65448500, -0.87478600, '0101000020E6100000FDF49F353FFEEBBF7D5C1B2AC6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31596397224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31596397224.webp', 'https://www.flickr.com/photos/zaragozaantigua/31596397224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23486, 'Plaza del Reino 1881', 'Grabado que reproduce de forma parcial el patio de la "Escuela de Artes y Oficios en Zaragoza", sita en la antigua Casa del Rey recayente a la plazuela o plaza del Reino, que desde finales del siglo XVIII era la sede de la Sociedad Econâ”œâ”‚mica de Amigos del Paâ”œآ،s, bajo cuyo impulso habâ”œآ،a sido constituida. Aâ”œâ–’os despuâ”œآ®s conocerâ”œآ،a el inicio de una nueva â”œآ®poca en un moderno y estiloso edificio de la antigua huerta de Santa Engracia construido al albur de la Exposiciâ”œâ”‚n Hispano-Francesa de 1908.', 1881, 1881, 1881, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65380300, -0.87446400, '0101000020E610000063F030ED9BFBEBBF6B8313D1AFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46846621125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46846621125.webp', 'https://www.flickr.com/photos/zaragozaantigua/46846621125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22048, 'Romareda 1956', 'Aâ”œآ®rea vista de Isabel la Catâ”œâ”‚lica, caracterizada por campos de cultivo y las torres agrâ”œآ،colas en el espacio delimitado por el Cuartel Palafox, la Feria de Muestras, la "Casa Grande", el Convento de Jerusalâ”œآ®n y el Seminario Conciliar.', 1956, 1956, 1956, 'Anos 50', 'UNIVERSIDAD', 41.63757500, -0.90280000, '0101000020E610000088855AD3BCE3ECBFA4DFBE0E9CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14869951680.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14869951680.webp', 'https://www.flickr.com/photos/zaragozaantigua/14869951680/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23488, 'Calle de Palafox c.1933', 'Imagen capturada en la calle del Chantre y centrada en la gran casa de los marqueses de Lazâ”œأ­n (luego de los Palafox) sita en la antigua calle del General (luego de Palafox). A la izquierda, vista parcial de la plaza del Reino. A la derecha, la esquina del novâ”œآ،simo Grupo Escolar Marcelino Lâ”œâ”‚pez Ornat, donde aparecen reunidos efectivos del Cuerpo de Seguridad y Asalto, posiblemente como consecuencia de los disturbios acontecidos durante la insurrecciâ”œâ”‚n anarquista de diciembre de 1933, que tuvo en esta zona uno de sus epicentros mâ”œأ­s violentos.', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65400400, -0.87438900, '0101000020E6100000B96DDFA3FEFAEBBF02BA2F67B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49630271236.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49630271236.webp', 'https://www.flickr.com/photos/zaragozaantigua/49630271236/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23539, 'Sitio de Zaragoza 1808', 'Siâ”œآ؟ge de Saragosse, Jules Girardet, 1906. Royal Albert Museum. En esta delirante pintura, que fue realizada un siglo despuâ”œآ®s de los hechos que narra, podemos ver a la derecha la iglesia zaragozana de San Nicolâ”œأ­s, ubicada en un entorno de fantasâ”œآ،a.', 1808, 1808, 1808, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65398600, -0.87261000, '0101000020E6100000B13385CE6BECEBBF5C0531D0B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15054009109.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15054009109.webp', 'https://www.flickr.com/photos/zaragozaantigua/15054009109/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23540, 'Maderas Nicolâ”œأ­s Hermanos c.1965', 'AHPZ. Archivo fotogrâ”œأ­fico Coyne. "Paso del Seâ”œâ–’or Atado a la Columna. Cofradâ”œآ،a del Seâ”œâ–’or Atado a la Columna y de Nuestra Seâ”œâ–’ora de la Fraternidad en el Mayor Dolor. Cofrades." Nocturno paso de la cofradâ”œآ،a con el fondo de la antigua empresa de maderas "Nicolâ”œأ­s Hermanos", sita en el Barrio de las Tenerâ”œآ،as, entre la plaza del mismo nombre y el Puente de Hierro, que queda a la izquierda de la imagen.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65379500, -0.87158900, '0101000020E6100000FEB4519D0EE4EBBFE8A4F78DAFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15085644857.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15085644857.webp', 'https://www.flickr.com/photos/zaragozaantigua/15085644857/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23558, 'Monasterio de Santo Sepulcro 1966', 'Vista desde el Coso Bajo de las traseras del Monasterio del Santo Sepulcro y su iglesia de San Nicolâ”œأ­s, en un conjunto construido en la antigua muralla de la ciudad. Fuente visual: Foto Leonardo Pâ”œآ®rez Obis, donada por â”œأ¼ngel Hernâ”œأ­ndez Mostajo para www.rafaelcastillejo.com', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65404100, -0.87206300, '0101000020E61000001AA721AAF0E7EBBF1F9F909DB7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22735616658.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22735616658.webp', 'https://www.flickr.com/photos/zaragozaantigua/22735616658/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23563, 'Plaza San Nicolâ”œأ­s 1965', 'Vista parcial de la plaza de San Nicolâ”œأ­s, con la calle del Sepulcro a la izquierda. A la derecha, fuera de campo, iglesia de San Nicolâ”œأ­s. Fuente visual: Foto Leonardo Pâ”œآ®rez Obis, donada por â”œأ¼ngel Hernâ”œأ­ndez Mostajo para www.rafaelcastillejo.com', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65402100, -0.87257100, '0101000020E61000003A048E041AECEBBFD8F2CAF5B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23165553771.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23165553771.webp', 'https://www.flickr.com/photos/zaragozaantigua/23165553771/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23567, 'Tumultos 1705', '"Tumultos en Zaragoza contra las tropas francesas", ilustraciâ”œâ”‚n de Fernando Fernâ”œأ­ndez Mota que prentende recrear el "motâ”œآ،n de Zaragoza" de 1705, cuando en el marco de la Guerra de Sucesiâ”œâ”‚n, austracistas locales, en la imagen con aires de baturros decimonâ”œâ”‚nicos, atacaron a un regimiento borbâ”œâ”‚nico francâ”œآ®s que pasaba por la ciudad camino del frente de guerra en Cataluâ”œâ–’a. El marco elegido es la plazuela de San Nicolâ”œأ­s, junto a la homâ”œâ”‚nima iglesia parroquial. Este episodio redundaba en la idea que presentaba al "pueblo" (concepto inexistente antes de la Revoluciâ”œâ”‚n Francesa de 1789) como globalmente partidario del bando austracista, lo que en el caso de la Zaragoza de la â”œآ®poca es muy temerario de afirmar, dados los bandazos o cambios de banderâ”œآ،a que las elites locales realizaron en funciâ”œâ”‚n del sentido de la guerra. Fuente visual: Historia de Espaâ”œâ–’a, Miguel Seguâ”œآ،, 1910, en todocoleccion.net.', 1705, 1705, 1705, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65409700, -0.87266200, '0101000020E610000050C8CEDBD8ECEBBFB3B45373B9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27226658288.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27226658288.webp', 'https://www.flickr.com/photos/zaragozaantigua/27226658288/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23570, 'Monasterio del Santo Sepulcro aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste que muestra las traseras del Monasterio del Santo Sepulcro, en la antigua muralla a la salida al Ebro del Coso Bajo. Al fondo, torre de la iglesia de San Nicolâ”œأ­s. Fuente: Lâ”œأ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65387200, -0.87211700, '0101000020E6100000E62329E961E8EBBF93E2E313B2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31597369614.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31597369614.webp', 'https://www.flickr.com/photos/zaragozaantigua/31597369614/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23579, 'Tenerâ”œآ،as 1930', 'Imagen centrada en la isleta reciâ”œآ®n embellecida que triangulaba el encuentro de la ribera del Ebro y las traseras del convento del Santo Sepulcro (a la derecha), el acceso al puente del Pilar, y el final del Coso Bajo. A la izquierda, los almacenes y serrerâ”œآ،a de Maderas Hermanos Nicolâ”œأ­s, el ingreso a la calle de Monreal y, al fondo, la plazuela de las Tenerâ”œآ،as. En el extremo superior de la isleta, la garita del Fielato de las Tenerâ”œآ،as Fuente visual: www.mecd.gob.es/.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65413700, -0.87187000, '0101000020E6100000F5A10BEA5BE6EBBF410DDFC2BAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36454484001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36454484001.webp', 'https://www.flickr.com/photos/zaragozaantigua/36454484001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23596, 'El Boterâ”œâ”‚n 1958', 'Ruinosa escena capturada durante el proceso de derribo de los antiguos inmuebles del barrio del Boterâ”œâ”‚n vertebrados por las calles del Garro, Retiro, Pallaruelo, Grillo, Monserrate y Lobo, que tras el derribo desaparecerâ”œآ،an del nomenclâ”œأ­tor urbano, sustituidas por la calle del Boterâ”œâ”‚n y la plaza de N.â”¬آ¬ S.â”¬آ¬ de la Piedad. Al fondo, alzado de los modernos edificios construidos y en construcciâ”œâ”‚n en torno al final de la calle de San Vicente de Paâ”œâ•‘l, que en este tramo antes se llamara del Conde de Alperche y que a la derecha chaflanea con el paseo de Echegaray y Caballero. En primer tâ”œآ®rmino y a la izquierda, un par de niâ”œâ–’as sentadas sobre una viga de madera de un edificio derribado, contemplan el arruinado escenario de este tradicional enclave zaragozano.', 1958, 1958, 1958, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65457800, -0.87315500, '0101000020E61000001BD82AC1E2F0EBBF2E573F36C9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52138231161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52138231161.webp', 'https://www.flickr.com/photos/zaragozaantigua/52138231161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23803, 'Vista de Zaragoza 1861', 'Vista de Zaragoza desde la margen izquierda del Ebro. "La torre campanil de La Seo, andamiada, despuâ”œآ®s de que un rayo incendiase y arruinase su chapitel (1850), permite establecer con precisiâ”œâ”‚n la cronologâ”œآ،a de la fotografâ”œآ،a, puesto que la torre permaneciâ”œâ”‚ andamiada y todavâ”œآ،a sin el nuevo chapitel, entre enero y marzo de 1861." Josâ”œآ® Antonio Hernâ”œأ­ndez Latas. Fuente: Fotâ”œâ”‚grafo: Mariano Jâ”œâ•‘dez y Ortiz, 1861. â”œأ¼lbum de Andrâ”œآ®s Martâ”œآ،n e Ipâ”œأ­s. Colecciâ”œâ”‚n Mariano Martâ”œآ،n Casalderrey, Zaragoza. Libro Primeros tiempos de la fotografâ”œآ،a en Zaragoza.', 1861, 1861, 1861, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65660300, -0.87030900, '0101000020E61000004A438D4292D9EBBF4DBA2D910BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15217164370.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15217164370.webp', 'https://www.flickr.com/photos/zaragozaantigua/15217164370/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24097, 'Calle del Sepulcro c.1959', 'Imagen capturada durante el recorrido que la procesiâ”œâ”‚n de la Cofradâ”œآ،a de Nuestra Seâ”œâ–’ora de la Piedad y del Santo Sepulcro realiza entre la iglesia de Santa Isabel de Portugal y la de San Nicolâ”œأ­s de Bari la madrugada del dâ”œآ،a 15 de abril, como es tradicional desde 1937. La escena, centrada en el paso de la carroza de la Virgen de la Piedad diseâ”œâ–’ada por los arquitectos Regino Borobio Ojeda y Josâ”œآ® Beltrâ”œأ­n Navarro, tiene lugar con el fondo edilicio de la antigua casa del siglo XVI que fuera de Juan Manente, luego de los marqueses de Almonacid, y desde finales del siglo XVII de los Esmir, en el tramo de la calle del Sepulcro entre la plaza de San Bruno y la moderna calle de San Vicente de Paâ”œâ•‘l. Esta vieja casona serâ”œآ،a derribada aâ”œâ–’os despuâ”œآ®s para modernizar la zona y desprovincionarla. Hemos volteado horizontalmente la original imagen para que tenga sentido arquitectâ”œâ”‚nico y visual, y la procesionaria pueda llegar correctamente a su destino.', 1959, 1959, 1959, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65499800, -0.87447500, '0101000020E61000005D6DC5FEB2FBEBBF037976F9D6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50117608373.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50117608373.webp', 'https://www.flickr.com/photos/zaragozaantigua/50117608373/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24234, 'P.â”¬â•‘ del Ebro 1895', '&quot;Orillas del Ebro en fiestas&quot;, imagen para tarjeta postal de Uniâ”œâ”‚n Universal de Correos. Toma de un grupo de personas, durante las fiestas del Pilar de 1895, posiblemente en la inauguraciâ”œâ”‚n del puente del Pilar, desde el que estarâ”œآ،a hecha la foto. Detrâ”œأ­s, edificios del tramo del paseo del Ebro entre la calle del Conde Alperche y la Puerta del Sol. Se non â”œآ؟ vero, â”œآ؟ ben trovato. Fuente: <a href=&quot;', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65512300, -0.87226700, '0101000020E61000003929CC7B9CE9EBBFC0ED0912DBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30808921363.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30808921363.webp', 'https://www.flickr.com/photos/zaragozaantigua/30808921363/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24616, 'Plaza del Reino c.1945', 'Captura desde la calle del Chantre. Al fondo, la Plaza del Reino, donde estuvo la Real Sociedad Econâ”œâ”‚mica de Amigos del Paâ”œآ،s. De derecha a izquierda cruza la calle Palafox. En la esquina de la derecha, chaflâ”œأ­n de la Casa de los Lazâ”œأ­n (luego, Palafox). Donde el seâ”œâ–’or de brazos cruzados, pared del Grupo Escolar Marcelino Lâ”œâ”‚pez Ornat. Aâ”œâ–’os despuâ”œآ®s todo esto cambiarâ”œأ­ radicalmente, con la apertura de la calle San Vicente de Paâ”œâ•‘l. Fuente Visual: ZARAGOZA instantâ”œأ­neas grises, Miguel Gay Berges.', 1945, 1945, 1945, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65397500, -0.87443200, '0101000020E61000008B6D52D158FBEBBF68B3EA73B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15225525578.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15225525578.webp', 'https://www.flickr.com/photos/zaragozaantigua/15225525578/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24622, 'Calle del Sepulcro c.1950', 'La calle del Sepulcro con la fachada de la antigua casa del siglo XVI que fuera de Juan Manente, de los marqueses de Almonacid, y desde finales del siglo XVII de los Esmir. Hacia la izquierda, la plaza de San Bruno. Esta gran casa con jardâ”œآ،n, derribada aâ”œâ–’os despuâ”œآ®s, llegaba por la parte de atrâ”œأ­s hasta el paseo de Echegaray y Caballero. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65491800, -0.87462500, '0101000020E6100000B0726891EDFCEBBFE7C75F5AD4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15728954176.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15728954176.webp', 'https://www.flickr.com/photos/zaragozaantigua/15728954176/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24624, 'Calle Sepulcro 1914', 'Resultado del hundimiento del edificio de la calle Sepulcro 24 de Zaragoza, a causa de los fuertes vientos desatados el lunes 25 de mayo de 1914. La imagen fue portada del diario ABC del jueves 28 de mayo de 1914.', 1914, 1914, 1914, 'Anos 10', 'CASCO HISTâ”œأ´RICO', 41.65464000, -0.87397100, '0101000020E610000098E0D40792F7EBBFA453573ECBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15903940602.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15903940602.webp', 'https://www.flickr.com/photos/zaragozaantigua/15903940602/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24641, 'Calle Palafox 1972', 'Imagen de la antigua casona de los marqueses de Lazâ”œأ­n, como remozo neoclâ”œأ­sico de un inmueble anterior del siglo XVI sito en una de las calles principales de la vieja capital del Reino. Su casual emplazamiento la salvâ”œâ”‚ de la piqueta que ejerciâ”œâ”‚ de bisturâ”œآ، cuando la apertura de la preciosa calle de San Vicente de Paâ”œâ•‘l reordenâ”œâ”‚ buena parte del antiguo barrio de la Seo. En la imagen, el antiguo palacio esquinero entre la calle de Palafox y la nueva vâ”œآ،a de comunicaciâ”œâ”‚n rodada. Al fondo, la catedral de San Salvador. Fuente visual: Gerardo Sancho Ramo (Archivo Pâ”œâ•‘blico Municipal).', 1972, 1972, 1972, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65407500, -0.87451900, '0101000020E6100000466117450FFCEBBFCB10C7BAB8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24128479981.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24128479981.webp', 'https://www.flickr.com/photos/zaragozaantigua/24128479981/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24652, 'Casa de los Lazâ”œأ­n c.1947', 'Imagen parcial del gran patio interior de la antigua casa de los Lazâ”œأ­n, desde 1890 usufructuado por la Hijas de la Caridad de San Vicente de Paâ”œâ•‘l, y centrada en las escaleras de acceso al Asilo de la Coronaciâ”œâ”‚n de la Virgen del Pilar, fundado en 1909 por el cardenal Soldevila, para niâ”œâ–’os marginados y excluidos. Cuando las condiciones materiales del antiguo palacio ya no den mâ”œأ­s de sâ”œآ، (poco despuâ”œآ®s de esta captura visual), y requieran una intervenciâ”œâ”‚n restauradora importante, el usufructo del edificio fue cedido a los herededos legales. Este espacio interior, luego, ha mutado a otra cosa. En la imagen, y a la izquierda, posiblemente el acceso desde la calle de Palafox, antigua del General del Reino. Fuente visual: foto Juan Mora Insa, en AHPZ.', 1947, 1947, 1947, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65419800, -0.87476300, '0101000020E6100000F20698F90EFEEBBFE78D93C2BCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32640854293.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32640854293.webp', 'https://www.flickr.com/photos/zaragozaantigua/32640854293/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24770, 'Ribera del Ebro 1977', 'Durante los prodigiosos aâ”œâ–’os del verticalismo y desarrollismo de los sesenta-setenta del siglo XX, con el ladrillo, el hormigâ”œâ”‚n y la especulaciâ”œâ”‚n desatada como seâ”œâ–’as de identidad, la ciudad fue objeto de una transformaciâ”œâ”‚n festejada en publirreportajes, no-dos, y preciosas postales que mostraban una nueva cara urbana moderna, avanzada, lustrosa, y joven. La construcciâ”œâ”‚n de infraestructuras y edificaciones de nueva planta, amâ”œآ®n de la ingente demoliciâ”œâ”‚n y piqueteo de inmuebles viejos, generaron un Everest de residuos que fueron gestionados a la brava, sin molestas perturbaciones legislativas, o polâ”œآ،ticas pâ”œâ•‘blicas, que trabaran el progreso. Tonelada tras tonelada, las riberas fluviales y la periferia periurbana fueron recrecidas en altura, y cientos de miles de deposiciones con cascotes de obra se convirtieron en la nueva especie dominante de esos parajes. En la imagen, captura del paisaje que mostraba la ribera del Ebro junto al Camino del Vado y la calle Lourdes. Al fondo, la ciudad de las torres catedralicias, tras el puente de hierros. Hubo un tiempo en que esto formaba parte del denominado "Soto del Caâ”œâ–’ar". Fuente visual: Archivo Pâ”œâ•‘blico Municipal, Gerardo Sancho Ramo.', 1977, 1977, 1977, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65502200, -0.86585900, '0101000020E6100000FD4FFEEE1DB5EBBF8C14CAC2D7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21656419220.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21656419220.webp', 'https://www.flickr.com/photos/zaragozaantigua/21656419220/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25149, 'Puente de las Tenerâ”œآ،as 1887', '"Inauguraciâ”œâ”‚n del puente de las Tenerâ”œآ،as". Medalla de bronce conmemorativa de la colocaciâ”œâ”‚n de la primera piedra del "puente de las Tenerâ”œآ،as", el 7 de mayo de 1887. Este proyecto no comenzâ”œâ”‚ a realizarse hasta 1891, inaugurâ”œأ­ndose en 1895 con el nombre de puente de Nuestra Seâ”œâ–’ora del Pilar, mâ”œأ­s conocido como de Hierro. Fuente visual: www.todocoleccion.net/', 1887, 1887, 1887, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65546400, -0.87088500, '0101000020E6100000757632384ADEEBBF49DA8D3EE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31030640815.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31030640815.webp', 'https://www.flickr.com/photos/zaragozaantigua/31030640815/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25160, 'Calle Monserrate aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste. Calle de Monserrate, que unâ”œآ،a la del Sepulcro con la ribera del Ebro. Fuente: Lâ”œأ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65485800, -0.87329700, '0101000020E6100000B83CD68C0CF2EBBF11C30E63D2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32062439830.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32062439830.webp', 'https://www.flickr.com/photos/zaragozaantigua/32062439830/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25168, 'Calle Retiro aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste. Confluencia de las calles del Retiro y del Garro (a la izquierda). Estas callejas se situarâ”œآ،an hoy en el entorno de la calle del Boterâ”œâ”‚n. Fuente: Lâ”œأ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65445700, -0.87324300, '0101000020E6100000ECBFCE4D9BF1EBBFB3D1393FC5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32440628885.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32440628885.webp', 'https://www.flickr.com/photos/zaragozaantigua/32440628885/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25182, 'Puente de las Tenerâ”œآ،as 1887', 'Grabado basado en una fotografâ”œآ،a que ilustra la ceremonia de colocaciâ”œâ”‚n de la primera piedra del nuevo puente de las Tenerâ”œآ،as sobre el râ”œآ،o Ebro, el 7 de mayo de 1887. La escena tiene lugar en el punto de arranque del primer estribo del nuevo puente en el barrio de las Tenerâ”œآ،as, en el tramo de la ribera comprendido entre las puertas del â”œأ¼ngel y del Sol. A este lugar todavâ”œآ،a se lo denominaba como de "Los Maderos", una reminiscencia del puente de Tablas o de Madera desaparecido en los albores del siglo. La ceremonia se desarrolla a primera hora de la tarde, con presencia del ministro de Fomento, Carlos Navarro Rodrigo, ademâ”œأ­s de la Corporaciâ”œâ”‚n municipal, encabezada por su alcalde-presidente Simâ”œâ”‚n Sâ”œأ­inz de Varanda, representantes de la Diputaciâ”œâ”‚n provincial y nutrida parroquia de pâ”œâ•‘blico asistente. Al fondo de la imagen, la margen izquierda, con el molino de harina, un lavadero y la Torre de Sala. Tras ellos deberâ”œآ،a despuntar la torre del antiguo convento de Jesâ”œâ•‘s, pero no lo hace. Este puente, como es usual en la ciudad, tiene una buena relaciâ”œâ”‚n de nombres que lo identifican: nuevo sobre el Ebro, de las Tenerâ”œآ،as, de la Virgen del Pilar, de Nuestra seâ”œâ–’ora del Pilar, y de Hierro, que suele ser la mâ”œأ­s extendida y funcional.', 1887, 1887, 1887, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65426800, -0.87173900, '0101000020E610000052BAF42F49E5EBBFE068C70DBFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49822067107.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49822067107.webp', 'https://www.flickr.com/photos/zaragozaantigua/49822067107/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25414, 'Ampliaciâ”œâ”‚n Puente de Hierro 1990', 'Vicente Modesto Locual. 1990 Desde 1895 el Puente de Hierro era uno uno de los principales accesos a la ciudad desde el norte (incluso tras la construcciâ”œâ”‚n del puente de Santiago), muy mayoritariamente para el gran anarquizante y devorador de espacios pâ”œâ•‘blicos que es el vehâ”œآ،culo privado. En la â”œâ•‘ltima dâ”œآ®cada del XX, el puente es profundamente remodelado bajo direcciâ”œâ”‚n de Javier Manterola: la estructura metâ”œأ­lica se repara, limpia y pinta, y se le aâ”œâ–’aden dos tableros laterales en forma de arco para derivar por ellos el paso de vehâ”œآ،culos. La plataforma central se reserva para uso peatonal, ese gran desconocido del urbanismo desarrollista y postdesarrollista franquista. La remodelaciâ”œâ”‚n finalizâ”œâ”‚ en 1991. En la imagen, aâ”œآ®rea visual desde la margen izquierda de la implementaciâ”œâ”‚n de los tableros laterales. Desde ese punto de vista, a la izquierda, estado de la ribera con las instalaciones fabriles de Pikolâ”œآ،n. En la otra orilla, a la derecha, la plaza de San Bruno sin las nuevas viviendas protegidas y, lâ”œâ”‚gicamente, convertida en aparcamiento en superficie.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65590700, -0.87050700, '0101000020E6100000E10CFE7E31DBEBBFD61BB5C2F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15182757080.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15182757080.webp', 'https://www.flickr.com/photos/zaragozaantigua/15182757080/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25434, 'Puente de Hierro 2011', 'Foto: Oliver Duch. Singular instantâ”œأ­nea tomada desde el puente de Nuestra Seâ”œâ–’ora del Pilar o de Hierro, el jueves 13 de octubre de 2011, al paso de la maqueta en cristal o "farol" de la basâ”œآ،lica del Pilar, con ella detrâ”œأ­s. Esta confluencia se dio, por primera vez, por el desvâ”œآ،o del Rosario de Cristal a causa de las obras del tranvâ”œآ،a. Participaron en la procesiâ”œâ”‚n las mâ”œأ­ximas autoridades en plaza: Luisa Fernanda Rudi, presidenta del Gobierno de Aragâ”œâ”‚n; Luis Marâ”œآ،a Beamonte, presidente de la Diputaciâ”œâ”‚n Provincial; y Juan Alberto Belloch, alcalde de Zaragoza. Fuente: Heraldo de Aragâ”œâ”‚n.', 2011, 2011, 2011, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65532300, -0.87140600, '0101000020E6100000BD38F1D58EE2EBBF87A8C29FE1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24763765578.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24763765578.webp', 'https://www.flickr.com/photos/zaragozaantigua/24763765578/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25442, 'Puente de Hierro 1991', 'Imagen capturada durante las pruebas de carga al final de las obras de ampliaciâ”œâ”‚n del puente de Hierro, denominada "abrazo del Ebro" por el amable acompaâ”œâ–’amiento de los dos nuevos viales para circulaciâ”œâ”‚n rodada, uno en cada direcciâ”œâ”‚n, al antiguo puente, cuyo uso fue reservado a viandantes, bicicletas, y animales irracionales. La toma se ha realizado desde las torres edilicias inmediatas al puente en la margen izquierda. Al otro lado del râ”œآ،o, visual del colegio de las Tenerâ”œآ،as, y a su izquierda, el solar sobre el que mâ”œأ­s tarde se construirâ”œآ،a el Pabellâ”œâ”‚n Deportivo Municipal de las Tenerâ”œآ،as, el Centro de Salud de la Rebolerâ”œآ،a, y algunas nuevas viviendas recayentes a la antigua calle del Râ”œآ،o. A la derecha, la glorieta donde estuviera la antigua Portaza, luego puerta del Sol. Fuente visual: "Asociaciâ”œâ”‚n de Vecinos Barrio de Jesâ”œâ•‘s. 30 aâ”œâ–’os de Historia".', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65554800, -0.87099000, '0101000020E6100000C993A46B26DFEBBFA77A32FFE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30532659566.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30532659566.webp', 'https://www.flickr.com/photos/zaragozaantigua/30532659566/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25450, 'Puente de Hierro 1990', 'Imagen capturada durante las obras de ampliaciâ”œâ”‚n del puente de Hierro mediante el aâ”œâ–’adido de dos tableros laterales en forma de arco por los que derivar el paso de la circulaciâ”œâ”‚n rodada (uno de ellos, a la derecha), mientras que la plataforma central, el histâ”œâ”‚rico puente (izquierda), se reservâ”œâ”‚ para uso peatonal. En la imagen, tomada desde la margen derecha, y al fondo, destacan algunas de las instalaciones de la antigua fâ”œأ­brica de colchones de Alfonso Solans, en la antigua calle del puente del Pilar, luego redenominada en homenaje a este local prâ”œâ”‚cer. Detrâ”œأ­s, en el camino del Vado, puede verse el colegio de la Purâ”œآ،sima y San Antonio. Fuente visual: archivo Heraldo de Aragâ”œâ”‚n, en "Padre Ebro. El râ”œآ،o Ebro y el siglo XX".', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65546400, -0.87088500, '0101000020E6100000757632384ADEEBBF49DA8D3EE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33960709815.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33960709815.webp', 'https://www.flickr.com/photos/zaragozaantigua/33960709815/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25458, 'Puente de Hierro 1990', 'Imagen capturada en el arranque del puente de Hierro o de Nuestra Seâ”œâ–’ora del Pilar desde la margen izquierda durante las obras de remodelaciâ”œâ”‚n que, bajo la direcciâ”œâ”‚n de Javier Manterola, repararon la estructura del puente inaugurado en 1895, y se le aâ”œâ–’adieron dos tableros laterales en forma de arco para derivar por ellos el trâ”œأ­nsito rodado. La plataforma central fue reservada para uso peatonal. En primer tâ”œآ®rmino, detalle del antiguo adoquinado del puente al descubierto por el desgaste de la superficial capa de asfalto a causa del intenso trâ”œأ­fico.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65648100, -0.87022600, '0101000020E6100000EB1F4432E4D8EBBF02B9C49107D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50308819236.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50308819236.webp', 'https://www.flickr.com/photos/zaragozaantigua/50308819236/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25459, 'Puente de Hierro 1990', 'Imagen capturada durante la remodelaciâ”œâ”‚n del puente de Nuestra Seâ”œâ–’ora del Pilar o de Hierro, que proyectada por el arquitecto Javier Manterola incluâ”œآ،a dos tableros laterales en forma de arco para el paso de vehâ”œآ،culos. Aquâ”œآ، figura el tablero occidental, tras el que al fondo y en la margen izquierda destacan los bloques de viviendas de las calles de Cecilio Navarro, Nicolâ”œأ­s de Funes y de Jesâ”œâ•‘s, recayentes a la homâ”œâ”‚nima plaza.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65539000, -0.87129900, '0101000020E61000003C33C170AEE1EBBF0E10CCD1E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50460967823.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50460967823.webp', 'https://www.flickr.com/photos/zaragozaantigua/50460967823/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25531, 'Ribera del Ebro c.1966', 'Fototeca Universidad de Sevilla. Aâ”œâ–’os 60. "Vista de Zaragoza". Imagen capturada desde la ribera izquierda del Ebro, entre el Puente del Pilar, o de Hierro, y el antiguo Molino de San Lâ”œأ­zaro, en un espacio entonces ocupado por lo que vemos. Al fondo, la soledad del enorme bloque 47-49 de San Vicente de Paâ”œâ•‘l (construido en 1954), y la fachada al Ebro de la Seo, el Palacio Arzobispal, la Lonja, el nuevo Ayuntamiento, y el Pilar. Fuente visual: fototeca.us.es/imagen.jsp?id=43768&tipo=v&elto=0&...', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65658600, -0.87148500, '0101000020E6100000C18BBE8234E3EBBF778192020BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15644187735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15644187735.webp', 'https://www.flickr.com/photos/zaragozaantigua/15644187735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21679, 'La Aljaferâ”œآ،a 1930', '"Castillo de la Aljaferâ”œآ،a".', 1930, 1930, 1930, 'Anos 30', 'DELICIAS', 41.65617600, -0.89651200, '0101000020E6100000F4160FEF39B0ECBFC6353E93FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14872302961.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14872302961.webp', 'https://www.flickr.com/photos/zaragozaantigua/14872302961/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25547, 'Vista Râ”œآ،o Ebro 1932', 'Desde el puente del Pilar, imagen panorâ”œأ­mica de la ciudad, el râ”œآ،o Ebro y el puente de Piedra. A la izquierda, la fachada del paseo de la Ribera, desde el convento del Sepulcro, y las ruinas del estribo en piedra del antiguo puente de Tablas, pasando por la Seo, el palacio Esmir y el palacio Arzobispal, hasta el Pilar. A la derecha, la arboleda de Macanaz. Composiciâ”œâ”‚n inâ”œآ®dita, democrâ”œأ­tica, cientâ”œآ،fica y popular, generada en los laboratorios del', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65580700, -0.87212500, '0101000020E61000009CC420B072E8EBBF73BED87BF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23224165536.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23224165536.webp', 'https://www.flickr.com/photos/zaragozaantigua/23224165536/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25549, 'Ebro c.1909', 'Desde el puente de Hierro una interesante vista hacia el râ”œآ،o Ebro y el puente de Piedra, con restos, a la derecha, del conglomerado pâ”œآ®treo, o estribo, sobre el que descansaba el acceso del antiguo puente de Tablas a la margen izquierda. A su lado, el que fuera Molino de San Lâ”œأ­zaro, ya en su dieciochesca ubicaciâ”œâ”‚n. Fuente visual: Estudio Coyne (DARA-AHPZ)', 1909, 1909, 1909, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65653600, -0.87131900, '0101000020E610000002452C62D8E1EBBFC652245F09D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23884124486.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23884124486.webp', 'https://www.flickr.com/photos/zaragozaantigua/23884124486/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25550, 'Puente de Hierro 1975', 'Turbamulta de baâ”œâ–’istas haciendo uso, en sus diversas modalidades, de una de las domâ”œآ®sticas playas del râ”œآ،o Ebro en su domesticado paso estival por la ciudad. Esta era la tradicional "Playa de las Hojalatas", cariâ”œâ–’oso apodo por la simpâ”œأ­tica y metâ”œأ­lica proliferaciâ”œâ”‚n de recipientes (usados) elaborados en hoja de lata, en el pedazo de ribera aledaâ”œâ–’a al entronque del puente del Pilar, o de Hierro, en la margen derecha. Al fondo, el torreado receptâ”œأ­culo de Nâ”¬آ¬ Sâ”¬آ¬ del Pilar, y el puente de Piedra. Un trolebâ”œâ•‘s de la lâ”œآ،nea del "Gâ”œأ­llego" transita por el puente, camino del Gâ”œأ­llego, unos meses antes de ser desmantelada por el progreso y los autobuses a â”œآ®l asociados. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65453500, -0.87085800, '0101000020E61000000FB8AE9811DEEBBF2F8B89CDC7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24223990960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24223990960.webp', 'https://www.flickr.com/photos/zaragozaantigua/24223990960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25551, 'Vista desde la Seo 1906', 'Vista desde la torre de la Seo del râ”œآ،o Ebro, en su crecida de 1906, con el puente de Hierro y el detalle del abigarrado caserâ”œآ،o cercano a la ribera, entre la catedral y el Coso Bajo. Al fondo se puede leer el cartel de "Maderas Nicolâ”œأ­s Hermanos". Fuente: www.zaragoza.es/contenidos/medioambiente/.../otros/catalo...', 1906, 1906, 1906, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65452200, -0.87358600, '0101000020E610000064CA87A06AF4EBBF9A417C60C7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24314983084.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24314983084.webp', 'https://www.flickr.com/photos/zaragozaantigua/24314983084/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25552, 'Vista Ebro 1907', 'Foto: Petit. Vista de la margen derecha del râ”œآ،o Ebro a su paso por Zaragoza, tomada desde el puente del Pilar en el otoâ”œâ–’o de 1907. A la izquierda, restos del estribo sobre el que se asentaba el antiguo puente de Tablas de la ciudad. Fuente: Ministâ”œآ؟re de la Culture (France) - Mâ”œآ®diathâ”œآ؟que de l''architecture et du patrimoine.', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65554800, -0.87099000, '0101000020E6100000C993A46B26DFEBBFA77A32FFE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24571307164.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24571307164.webp', 'https://www.flickr.com/photos/zaragozaantigua/24571307164/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25556, 'Vista desde el Ebro 1907', 'Foto: Petit. Vista de Zaragoza desde la margen izquierda del râ”œآ،o Ebro en el otoâ”œâ–’o de 1907. A la derecha, restos del estribo sobre el que se asentaba el antiguo puente de Tablas de la ciudad. Fuente: Ministâ”œآ؟re de la Culture (France) - Mâ”œآ®diathâ”œآ؟que de l''architecture et du patrimoine.', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65653600, -0.87131900, '0101000020E610000002452C62D8E1EBBFC652245F09D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25108644621.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25108644621.webp', 'https://www.flickr.com/photos/zaragozaantigua/25108644621/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25560, 'Râ”œآ،o Ebro 1910', 'Foto: Charles Jacquin. Placa autocroma de una vista de Zaragoza desde la margen izquierda del râ”œآ،o Ebro y a espaldas del puente de N.â”¬آ¬ S.â”¬آ¬ del Pilar. En primer tâ”œآ®rmino y a la derecha, restos del estribo norte del antiguo puente de Tablas donde terminaba el homâ”œâ”‚nimo camino que conectaba con la calle de Jesâ”œâ•‘s, junto al lavadero de Modesto Andrâ”œآ®s. Detrâ”œأ­s de este estribo se encontraba el antiguo molino de sal de San Lâ”œأ­zaro alimentado por la acequia del Rabal, que desde 1907 funcionaba como molino harinero del Puente de Tablas accionado ademâ”œأ­s por un motor elâ”œآ®ctrico, lo que le permitâ”œآ،a moler el grano أ”أ‡آ£a cualquier hora del dâ”œآ،a y en toda â”œآ®pocaأ”أ‡أک. Al fondo, el puente de Piedra donde destaca el aspecto de su tercera pila, con bloques de piedra sobre su baja estructura. Por encima suyo, aspecto de la fachada al râ”œآ،o del tramo edilicio entre el Seminario y el templo del Pilar. Fuente visual: bibliotheques-specialisees.paris.fr/', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œأ´RICO', 41.65653600, -0.87131900, '0101000020E610000002452C62D8E1EBBFC652245F09D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28396195976.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28396195976.webp', 'https://www.flickr.com/photos/zaragozaantigua/28396195976/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25566, 'Râ”œآ،o Ebro 1910', 'Placa autocroma de una vista capturada desde el puente de Hierro, con interesante visual del râ”œآ،o Ebro, el puente de Piedra, restos del estribo sur del antiguo puente de Tablas, y el correspondiente tramo de la margen derecha. Al fondo, la torre de la Seo y las dos del Pilar. Fuente visual: Charles Jacquin photographe bibliotheques-specialisees.paris.fr/', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œأ´RICO', 41.65560300, -0.87195100, '0101000020E610000027DD96C805E7EBBF6A1492CCEAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32935866406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32935866406.webp', 'https://www.flickr.com/photos/zaragozaantigua/32935866406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25575, 'Râ”œآ،o Ebro 1909', 'Imagen capturada en la margen izquierda, donde la playa de cantos rodados a espaldas del lavadero de la calle de Jesâ”œâ•‘s inmediato al puente de N.â”¬آ¬ S.â”¬آ¬ del Pilar, con una interesante vista del râ”œآ،o Ebro con el fondo del tramo de la margen derecha con el que confrontaba. En la orilla y al fondo a la izquierda destacan los restos del estribo del antiguo puente de Tablas o Madera. Tras el arbolado paseo del Ebro, edificios comprendidos entre â”œآ®ste y las calles de Monserrate, Grillo, Silencio y Conde de Alperche, en cuyos bajos se abrâ”œآ،an varios establecimientos de construcciâ”œâ”‚n y alquiler de carros, ademâ”œأ­s de tratantes de caballerâ”œآ،as. A continuaciâ”œâ”‚n, la gran casa que fuera de los Esmir (donde emerge al fondo el cimborrio de la Seo), seguida por el palacio Arzobispal (donde destaca la barroca torre de la Seo).', 1909, 1909, 1909, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65614400, -0.87287600, '0101000020E610000052D32EA699EEEBBFBABBCE86FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52235254996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52235254996.webp', 'https://www.flickr.com/photos/zaragozaantigua/52235254996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25996, 'Vista Puente Hierro c.1942', 'Vista aâ”œآ®rea de la zona del Puente del Pilar, o de Hierro. En la margen derecha, visual del edificio de la Serrerâ”œآ،a Nicolâ”œأ­s (a la derecha del jardâ”œآ،n triangular) y el complejo de los edificios de nuevo y ribereâ”œâ–’o Cuartel de Automovilismo. En la margen izquierda, el Barrio de Jesâ”œâ•‘s, los enormes lavaderos de Modesto Andrâ”œآ®s, y el cuartel de San Lâ”œأ­zaro.', 1942, 1942, 1942, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65554800, -0.87099000, '0101000020E6100000C993A46B26DFEBBFA77A32FFE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20892928843.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20892928843.webp', 'https://www.flickr.com/photos/zaragozaantigua/20892928843/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26010, 'Vista aâ”œآ®rea 2006', 'Foto: Juan Carlos Arcos. Panorâ”œأ­mica de Zaragoza desde el paseo de Echegaray y Caballero, con parte de las instalaciones de la fâ”œأ­brica de armamento Instalaza, a la izquierda. A la derecha, antes del puente de Hierro aâ”œâ•‘n sin pintar de azul, el reciâ”œآ®n creado parque ribereâ”œâ–’o que serâ”œأ­ desmantelado poco despuâ”œآ®s para hacer otro similar, en un ejercicio de lucrativo quita y pon propio del perâ”œآ،odo. Fuente: Heraldo de Aragâ”œâ”‚n, 18 de junio de 2006.', 2006, 2006, 2006, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65381700, -0.86929500, '0101000020E6100000377172BF43D1EBBFCF488446B0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22299638391.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22299638391.webp', 'https://www.flickr.com/photos/zaragozaantigua/22299638391/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26050, 'Vista panorâ”œأ­mica c.1904', 'Postal panorâ”œأ­mica coloreada que muestra la margen derecha del râ”œآ،o Ebro, desde el puente del Pilar hasta el de Piedra. Se distinguen las torres de San Nicolâ”œأ­s, la Magdalena, la Seo y el Pilar. Fuente: www.todocoleccion.net', 1904, 1904, 1904, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65607300, -0.87354600, '0101000020E6100000D7A6B1BD16F4EBBFF1643733FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32022513125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32022513125.webp', 'https://www.flickr.com/photos/zaragozaantigua/32022513125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21020, 'San Pablo &quot;antigua mezquita&quot; 1869', 'Tomando como referencia un dibujo de Genaro Pâ”œآ®rez de Villa-Amil realizado la dâ”œآ®cada anterior, la revista "El Museo Universal" en su nâ”œâ•‘mero 46 (14-XI-1869) publicâ”œâ”‚ esta ilustraciâ”œâ”‚n con un intrigante pie de imagen que asevera que la iglesia parroquial de San Pablo fue "antigua mezquita". El cuerpo del texto del reportaje ahonda mâ”œأ­s en el misterio, al apuntar "un carâ”œأ­cter oriental, imposible de confundir con ningun (sic) otro estilo arquitectâ”œâ”‚nico", que despojado "de los revestimientos modernos" muestra "las lâ”œآ،neas magistrales de la ya purificada mezquita". Por supuesto, mezquita, o no, la dataciâ”œâ”‚n cronolâ”œâ”‚gica sigue siendo la canâ”œâ”‚nica cristiana: comienzos del siglo XII, tras la conquista cristiana, cuando en pocos aâ”œâ–’os, y por arte de "birlibirloque", Saragoâ”œآ؛a se convirtiâ”œâ”‚, segâ”œâ•‘n los grandes estudiosos locales del arte cristiano, en el nâ”œâ•‘cleo mâ”œأ­s densamente poblado por iglesias, parroquias y ermitas româ”œأ­nicas de nueva planta de todo el occidente cristiano europeo, en paralelo a la fantâ”œأ­stica desapariciâ”œâ”‚n de todos los edificios religiosos de la Saraqusta musulmana que habâ”œآ،an prestado servicio durante los 400 aâ”œâ–’os anteriores. No obstante, cuando siglos despuâ”œآ®s se ha procedido a restaurar algunos de estos edificios "româ”œأ­nicos", no se han detectado apenas trazas româ”œأ­nicas de relieve, y sâ”œآ،, de siglos anteriores. El texto apunta una posibilidad menos delirante, cuando introduce el concepto "purificada mezquita": mediante ceremoniales rituales, se despoja a un edificio o estructura de sus efluvios moriscos, y se le reconvierte en un edificio cristiano "de toda la vida". Una aplicaciâ”œâ”‚n del arte de reciclar y reutilizar, "avant la lettre", que fue aplicado cientâ”œآ،ficamente en esta ciudad, comenzando por su referencial Mezquita Aljama construida por Hanas ibn cAbd Allah as-Sancâ”œأ­ni, y ampliada luego, que tras su "purificaciâ”œâ”‚n" serâ”œأ­ denominada por los invasores cristianos como "Seo de San Salvador". Esta nueva versiâ”œâ”‚n del dibujo muestra algunas variaciones respecto del original, com', 1869, 1869, 1869, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65613400, -0.88619500, '0101000020E6100000791EDC9DB55BECBF97E5EB32FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19921997159.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19921997159.webp', 'https://www.flickr.com/photos/zaragozaantigua/19921997159/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21033, 'Plaza del Mercado 1868', 'Plaza del Mercado capturada desde la altura de las calles Cerdâ”œأ­n y Escuelas Pâ”œآ،as. Al fondo, la calle de Antonio Pâ”œآ®rez, conducente a la puerta de San Ildefonso y el paseo del Ebro. De la macizada manzana entre la plaza de San Antâ”œâ”‚n y San Juan de los Panetes emerge la Zuda. Fuente visual: Frank Mason Good, en la exposiciâ”œâ”‚n ''Zaragoza estereoscâ”œâ”‚pica. Fotografâ”œآ،a profesional y comercial''', 1868, 1868, 1868, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65614200, -0.88307000, '0101000020E6100000E08442041C42ECBF1AC40776FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26477064146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26477064146.webp', 'https://www.flickr.com/photos/zaragozaantigua/26477064146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21042, 'Procesiâ”œâ”‚n del Pilar 1860', 'Dibujo de la procesiâ”œâ”‚n de la Virgen del Pilar realizada la desapacible tarde del 12 de octubre e inmortalizada pues tuvo como partâ”œآ،cipes a la reina Isabel II, al rey Francisco de Asâ”œآ،s de Borbâ”œâ”‚n, y al prâ”œآ،ncipe de Asturias Alfonso de Borbâ”œâ”‚n, ya que coincidiâ”œâ”‚ con su viaje oficial a Zaragoza realizado ese aâ”œâ–’o. Esta nutrida procesiâ”œâ”‚n saliâ”œâ”‚ del templo del Pilar y recorriâ”œâ”‚ las câ”œآ®ntricas calles de la Sombrererâ”œآ،a, de la Virgen y del Arco de Toledo, la plaza del Mercado, las calles de la Albarderâ”œآ،a y del Coso, la plaza de la Constituciâ”œâ”‚n, las calles de San Gil, de San Pedro, de la Virgen del Rosario, de la Cuchillerâ”œآ،a, del Pilar, hasta desembocar en la plaza del Pilar. En el dibujo destaca la imagen en plata de la Virgen del Pilar precedida de los Infanticos y conducida en andas entre las filas de canâ”œâ”‚nigos que portan el palio. Siguen despuâ”œآ®s los concejales precedidos de los maceros municipales, las autoridades de la Diputaciâ”œâ”‚n provincial y la familia Real. La Reina destaca con traje cubierto de encajes blancos y la corona real sobre sus sienes. Junto a ella, el Rey vestido en uniforme de Capitâ”œأ­n general del Ejâ”œآ®rcito. En el Gran Archivo Zaragoza Antigua (GAZA) ubicamos este dibujo, posiblemente, en la plaza del Mercado. Fuente visual: dibujo y litografâ”œآ،a de Vicente Urrabieta realizada en el establecimiento litogrâ”œأ­fico de Josâ”œآ® Donâ”œâ”‚n (Madrid), aparecida en "Crâ”œâ”‚nica del viaje de sus Majestades Altezas reales a las Islas Baleares, Cataluâ”œâ–’a y Aragâ”œâ”‚n en 1860" (Antonio Flores Algovia, 1861), y coloreada en echosinhache.blogspot.com/', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65607400, -0.88306700, '0101000020E61000009CA8A5B91542ECBFC1E09A3BFAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45402694302.webp', 'https://ktnavneugmimhdvpn