INSERT INTO public.photos VALUES (21051, 'San Pablo ca. 1870', 'Archivo RUIZ VERNACCI, Jean Laurent y Câ”œآ،a. 1860-1886. "Torre de la Iglesia de San Pablo".', 1870, 1870, 1870, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65607200, -0.88608900, '0101000020E61000000F0D8B51D75AECBF21E9D32AFAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14680088698.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14680088698.webp', 'https://www.flickr.com/photos/zaragozaantigua/14680088698/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21085, 'Calle San Blas 1871', '"Zaragoza. Algunos habitantes disponen su marcha huyendo de la inundaciâ”œâ”‚n". Dibujo alusivo a las inundaciones del râ”œآ،o Ebro de enero de 1871. Al fondo, la torre de la iglesia de San Pablo. Fuente: Revista La Ilustraciâ”œâ”‚n, Madrid. A travâ”œآ®s de www.facebook.com/photo.php?fbid=10205887851115259&set...', 1871, 1871, 1871, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65676600, -0.88832800, '0101000020E6100000F4DF83D72E6DECBFF78F85E810D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30944154665.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30944154665.webp', 'https://www.flickr.com/photos/zaragozaantigua/30944154665/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21110, 'San Pablo 1889', '"Saragosse. Tour de l''Eglise St-Paul". Fuente: J. Lâ”œآ®vy et Cie, en "Zaragoza en la mirada ajena", Cortes de Aragâ”œâ”‚n, 2012.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65588600, -0.88609200, '0101000020E610000053E9279CDD5AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22725342475.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22725342475.webp', 'https://www.flickr.com/photos/zaragozaantigua/22725342475/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21197, 'Calle de las Escuelas Pâ”œآ،as c.1898', 'Imagen con la primera ubicaciâ”œâ”‚n productiva y comercial de la empresa Chocolates Orâ”œâ•‘s establecida por Joaquâ”œآ،n Orâ”œâ•‘s Abadâ”œآ،a en 1898 en el nâ”¬â•‘ 19 de la calle de las Escuelas Pâ”œآ،as, chaflanera con el nâ”¬â•‘ 2 de la calle de Basilio Boggiero (a la izquierda). Aquâ”œآ، estuvo previamente la fâ”œأ­brica de chocolates y tienda de ultramarinos de Pedro Gâ”œâ”‚mez, y en la imagen albergaba la factorâ”œآ،a de Orâ”œâ•‘s y el comercio La Abeja Colonial de Seuba&Carbonell.', 1898, 1898, 1898, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65491800, -0.88447400, '0101000020E61000009831056B9C4DECBFE7C75F5AD4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51334556070.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51334556070.webp', 'https://www.flickr.com/photos/zaragozaantigua/51334556070/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21295, 'Plaza del Mercado c.1900', 'Imagen de la antigua plaza del Mercado, capturada desde cierta altura en la manzana entre las calles de las Escuelas Pâ”œآ،as, y de Juan Jimâ”œآ®nez Cerdâ”œأ­n. El enfoque estâ”œأ­ centrado en la fachada oriental de la plaza, comprendida entre los nâ”œâ•‘meros 41 (izquierda), junto a la calle Manifestaciâ”œâ”‚n, y 69 (derecha), junto a la calle de la Torre Nueva. Destacan los soportales entoldados, a nivel de calle, entre los que se instalaban los puestos del mercado. Esta fachada formaba parte de la manzana de viviendas entre la plaza del Mercado y la calle de Lanuza, en cuya zona central, longitudinalmente, y enmascarado por las viviendas, estaba localizado uno de los tramos de la antigua muralla de piedra de la ciudad. Sobre el firme aparece el trazado de la tranviaria lâ”œآ،nea "Circunvalaciâ”œâ”‚n", que ingresaba en la plaza por la calle de Cerdâ”œأ­n. Poco tiempo despuâ”œآ®s, esta manzana serâ”œآ،a integralmente derribada para iniciar la construcciâ”œâ”‚n del nuevo Mercado de la ciudad. Esta monumental imagen fue convertida por la Fototipia de Lucas Escolâ”œأ­ en comercial postal de la serie "Zaragoza", con el nâ”œâ•‘mero 43, y titulada "Antiguo Mercado". Fuente visual: www.ebay.es/', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65584600, -0.88318800, '0101000020E61000005B07077B1343ECBF309B00C3F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31215207052.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31215207052.webp', 'https://www.flickr.com/photos/zaragozaantigua/31215207052/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21471, 'San Pablo Apâ”œâ”‚stol 1912', 'Imagen de la iglesia parroquial de San Pablo Apâ”œâ”‚stol centrada en su singular atalaya.', 1912, 1912, 1912, 'Anos 10', 'CASCO HISTâ”œأ´RICO', 41.65600800, -0.88620100, '0101000020E610000002D71533C25BECBF0AF5F411F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53580689263.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53580689263.webp', 'https://www.flickr.com/photos/zaragozaantigua/53580689263/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21843, 'Calle Conde de Aranda 1933', 'Imagen capturada en el interior del nuevo Monumental Cinema poco antes de su inauguraciâ”œâ”‚n, cinematâ”œâ”‚grafo de la empresa de Hermâ”œâ”‚genes Herrero proyectado por el arquitecto Marcelo Carquâ”œآ® con capacidad para 2319 personas. De estilo moderno, racionalista, y monumentales dimensiones, tenâ”œآ،a su entrada principal en la calle del Conde de Aranda nâ”¬â•‘ 32, y contaba con una salida en la calle de Boggiero nâ”¬â•‘ 47. Fue clausurado 39 aâ”œâ–’os despâ”œâ•£â”œآ®s, y su enorme solar reurbanizado de forma bien provechosa. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65514400, -0.88703700, '0101000020E610000045F12A6B9B62ECBFD71533C2DBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35602884753.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35602884753.webp', 'https://www.flickr.com/photos/zaragozaantigua/35602884753/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21846, 'Calle de Cerdâ”œأ­n 1934', 'Imagen capturada en el tramo de la calle de Cerdâ”œأ­n conducente al Mercado Central, y centrada en la modernâ”œآ،sima fachada (tras reciente reforma) de la gran zapaterâ”œآ،a Calzados el Siglo XX, de la viuda de Miguel Ferrer, que vio iniciar su actividad en las postrimerâ”œآ،as del siglo XIX. El tradicional y muy demandado gâ”œآ®nero de las alpargatas y zapatillas tenâ”œآ،a un acceso propio desde la trasera calle de las Escuelas Pâ”œآ،as, junto a la entrada a la calle de San Pablo. Este establecimiento estaba especializado en un nuevo tipo de zapato para la seâ”œâ–’ora y el niâ”œâ–’o (sic) denominado "Checo". Sobre el firme, en primer tâ”œآ®rmino, y hacia la derecha, tendido tranviario de la lâ”œآ،nea Ayuntamiento-Portillo, originalmente de la lâ”œآ،nea Circunvalaciâ”œâ”‚n como ramal plaza de la Constituciâ”œâ”‚n-Puente de Piedra por el Mercado. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65520000, -0.88392600, '0101000020E6100000EAB0C22D1F49ECBF6B2BF697DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35661297254.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35661297254.webp', 'https://www.flickr.com/photos/zaragozaantigua/35661297254/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21854, 'Calle de Torre Nueva 1932', 'Imagen centrada en la gran fachada de la casa de los condes de Bureta en el nâ”¬â•‘ 6 de la calle de Torre Nueva cuando ya pendâ”œآ،a sobre ella la amenaza de derribo, algo que se consumarâ”œآ،a tres aâ”œâ–’os despuâ”œآ®s. Ya en el siglo XV y cuando la calle se denominaba Nueva del Mercado, esta era la casa de los Lâ”œâ”‚pez de Villanova, que en el siglo XVII pasâ”œâ”‚ a los condes de Bureta. La original y tradicional fachada de la casona era en ladrillo caravista y culminaba en galerâ”œآ،a de arquillos y alero saliente. Fue revocada despuâ”œآ®s en yeso, abriâ”œآ®ndose grandes balcones y ventanales regulares, como la imagen ilustra. A la derecha del edificio, e inmediato, el acceso a la empinada calle de Antâ”œâ”‚n Trillo y a la plaza de Lanuza. Fuente visual: www.mecd.gob.es/.', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65533100, -0.88303200, '0101000020E610000080492A53CC41ECBF0987DEE2E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35882023093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35882023093.webp', 'https://www.flickr.com/photos/zaragozaantigua/35882023093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21937, 'San Pablo aâ”œâ–’os 40', 'San Pablo, aguafuerte, Jesâ”œâ•‘s Fernâ”œأ­ndez Barrio, Diputaciâ”œâ”‚n de Zaragoza, c. 1945-1947. Iglesia de San Pablo de Zaragoza. Fuente: web.dpz.es/arscatalogi.es/', 1940, 1940, 1949, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65621600, -0.88624400, '0101000020E6100000D4D688601C5CECBF548EC9E2FED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15257156253.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15257156253.webp', 'https://www.flickr.com/photos/zaragozaantigua/15257156253/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22073, 'San Pablo 1953', 'Imagen de la puerta principal y la torre de la parroquia de San Pablo. La pâ”œآ®trea fachada y los jarrones incrustados que luce son una impostaciâ”œâ”‚n del siglo XVIII, cuando se recubriâ”œâ”‚ con piedra el ladrillo de la fâ”œأ­brica original. Fuente visual: "Aragâ”œâ”‚n : revista grâ”œأ­fica de cultura aragonesa" (Aâ”œâ–’o XXVIII, Nâ”¬â•‘ 227, abril-junio 1953).', 1953, 1953, 1953, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65588600, -0.88609200, '0101000020E610000053E9279CDD5AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15507137488.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15507137488.webp', 'https://www.flickr.com/photos/zaragozaantigua/15507137488/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22206, 'San Pablo 1955', '"Nocturno en San Pablo", â”œâ”‚leo sobre lienzo, Josâ”œآ® Baquâ”œآ® Ximâ”œآ®nez, 1955. Vista del caserâ”œآ،o del barrio de San Pablo, con la torre mudâ”œآ®jar de la iglesia homâ”œâ”‚nima presidiendo rotunda el paisaje. Fuente: baqueximenez.weebly.com', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65613400, -0.88619500, '0101000020E6100000791EDC9DB55BECBF97E5EB32FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40209712155.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40209712155.webp', 'https://www.flickr.com/photos/zaragozaantigua/40209712155/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22297, 'San Pablo c.1965', 'Plaza e iglesia de San Pablo. Fuente: AMZ.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65577800, -0.88585100, '0101000020E6100000EB1F4432E458ECBFD8B79388F0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15480355226.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15480355226.webp', 'https://www.flickr.com/photos/zaragozaantigua/15480355226/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22389, 'Calle Zamoray 1968', 'Chaflâ”œأ­n entre las calles de Agustina de Aragâ”œâ”‚n (izquierda) y Josâ”œآ® Zamoray (derecha). Fuente visual: Foto Leonardo Pâ”œآ®rez Obis, donada por â”œأ¼ngel Hernâ”œأ­ndez Mostajo para www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65473200, -0.88824100, '0101000020E610000039ECBE63786CECBF85D21742CED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22727732317.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22727732317.webp', 'https://www.flickr.com/photos/zaragozaantigua/22727732317/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22452, 'Calle General Franco 1967', 'Foto: Emilio Aure Durbâ”œأ­n. Vista de la calle del General Franco, con la zona del Portillo al fondo. A la derecha, en el nâ”œâ•‘mero 32, cartel del Cine Monumental, inaugurado en 1933 como "Monumental Cinema" y clausurado en 1972. Fuente visual: www.facebook.com/photo.php?fbid=1802072866697326&set=...', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65493800, -0.88719100, '0101000020E6100000F3C64961DE63ECBF2E742502D5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31419929176.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31419929176.webp', 'https://www.flickr.com/photos/zaragozaantigua/31419929176/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22458, 'Iglesia de San Pablo c.1963', 'Iglesia de San Pablo. â”œأ´leo de Juliâ”œأ­n Borreguero. Vista de la plaza de San Pablo, con la fachada de la iglesia adornada con los aâ”œâ–’adidos del siglo XVIII que serâ”œأ­n retirados en 1977. Fuente: www.arteinformado.com/', 1963, 1963, 1963, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65588600, -0.88609200, '0101000020E610000053E9279CDD5AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31810772780.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31810772780.webp', 'https://www.flickr.com/photos/zaragozaantigua/31810772780/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22492, 'Calle del General Franco 1968', 'Imagen capturada en el adoquinado tramo inicial de la calle del General Franco, entre el colegio de los Escolapios y el inmueble del nâ”¬â•‘ 28, a la izquierda. Centra la escena la composiciâ”œâ”‚n tranviaria M59+R87 de la lâ”œآ،nea 5 "Venecia-Delicias" encaminada hacia la terminal de la plaza de Huesca. Tras ella, la desaparecida fachada edilicia de la manzana entre la calle de Miguel de Ara y la de Ramâ”œâ”‚n y Cajal. A la derecha extrema sobresale el torreâ”œâ”‚n occidental del palacio de la Audiencia, y algunos de los anuncios comerciales que culminaban el arranque de la desaparecida manzana entre la calle de Cerdâ”œأ­n y la de las Escuelas Pâ”œآ،as. Fuente visual: foto Charles F. Firminger en "30937 Transport Photograph Database".', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65473500, -0.88642500, '0101000020E6100000E86A2BF6975DECBFF645425BCED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46933109132.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46933109132.webp', 'https://www.flickr.com/photos/zaragozaantigua/46933109132/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22568, 'Rastro del Mercado 1975', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Junio 1975. "Rastro del Mercado." Zaragoza 100%: estâ”œأ­ pegando un sol enorme, pero no por ello hay que buscar la sombra: con ponerse un periâ”œâ”‚dico en la cabeza, vale. Imagen del rastro, secciâ”œâ”‚n sables, braseros, candelabros y quincalla varia, en el entorno de la puerta principal de acceso al Mercado Central, inmediata a la calle Cerdâ”œأ­n, calle a la que le quedaba apenas una legislatura de vida.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65559900, -0.88345500, '0101000020E6100000139B8F6B4345ECBF292504ABEAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15246198251.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15246198251.webp', 'https://www.flickr.com/photos/zaragozaantigua/15246198251/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
