INSERT INTO public.photos VALUES (22655, 'San Pablo 1977', 'La iglesia parroquial de San Pablo ha sido objeto, a lo largo de su extensa historia desde que fuera alminar del arrabal musulmâ”œأ­n al oeste de la ciudad, de numerosas modificaciones en su fâ”œأ­brica, aspecto, y espacio interior. A finales del siglo XVIII su fachada y portada de acceso principal, en la calle de San Pablo, fueron profusamente reformadas con elementos tardo-neoclâ”œأ­sicos. Asâ”œآ،, el muro fue revestido de piedra, y decorado con pilastras lisas, una cornisa superior y hornacinas con jarrones. Posteriores restauraciones han eliminado toda esta traza, excepto en la puerta de ingreso. En la imagen, captura del exterior del muro de la iglesia de San Pablo, con el arrasamiento de los aâ”œâ–’adidos de finales del XVIII, en la bâ”œâ•‘squeda del previo muro mudâ”œآ®jar. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1977, 1977, 1977, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65588600, -0.88609200, '0101000020E610000053E9279CDD5AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21655866670.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21655866670.webp', 'https://www.flickr.com/photos/zaragozaantigua/21655866670/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
